@ARTICLE{10.1002/hsr2.71404,
	author = {Parizad N and Hassanpour A and Goli R and Khalkhali H and Nozad A},
	title = {The Effect of Foot Reflexology on Sleep Quality in Patients With Chronic Lymphocytic Leukemia Under Chemotherapy: A Randomized Controlled Trial.},
	journal = {Health Sci Rep},
	year = {2025},
	abstract = {BACKGROUND AND AIMS: Chronic lymphocytic leukemia (CLL) frequently causes a range of physical and psychological symptoms, including disrupted sleep. Foot reflexology is thought to promote relaxation and improve sleep quality. This study evaluated its effectiveness in patients with CLL undergoing chemotherapy. METHODS: A single-blind randomized controlled trial was conducted with 68 participants (n = 68), who were assigned either to an intervention group or a control group. The intervention group received daily 10-min foot reflexology sessions for 4 weeks using sweet almond oil, while the control group received standard routine care, including monitoring of vital signs, symptom management, medication administration, psychological support, and general patient education according to oncology ward protocols. Sleep quality was assessed at baseline and after the intervention using the Pittsburgh Sleep Quality Index (PSQI). Data were analyzed with SPSS version 25, using chi-square tests, Fisher's exact test, and t-tests. RESULTS: At baseline, there was no significant difference in PSQI scores between groups (Reflexology: 16.30 ± 1.29 vs. Control: 16.78 ± 1.38; p = 0.143). After the intervention, the reflexology group showed a marked improvement in sleep quality compared to the control group (11.78 ± 1.47 vs. 16.21 ± 1.40; p < 0.001). The effect size was very large and clinically meaningful (Cohen's d = 3.08, 95% CI: 2.55-3.61). Within-group analysis confirmed significant improvement in the reflexology group (t = 6.161, p < 0.001; Cohen's d = 3.50), whereas no significant change was observed in the control group (t = -1.559, p = 0.136). CONCLUSIONS: Foot reflexology appears to be a safe and effective complementary intervention to improve sleep quality in patients with CLL. However, the study's limitations, including the lack of a sham control, short-term follow-up, and a relatively small sample size, should be considered. Healthcare providers may cautiously incorporate reflexology into supportive care, ensuring integration with standard treatments and professional guidance.},
	doi = {10.1002/hsr2.71404},
	pmid = {41132190},
	note = {PMC12540198}
}

@ARTICLE{10.3389/frhem.2025.1550681,
	author = {Maslana KE and Skogerboe GE and Sborov DW and Coletta AM},
	title = {Exercise and Diet Studies Among Patients Living with Multiple Myeloma: Current Evidence and Considerations of Patient Preferences.},
	abstract = {BACKGROUND: Multiple myeloma (MM) is the second most common blood cancer after leukemia in adults. Despite advancements in treatment that have extended survival, MM remains incurable and the cancer and its treatment result in adverse acute, long-term and latent side-effects, necessitating a focus on strategies to attenuate these side-effects and improve quality of life. This narrative review highlights MM patient preferences for exercise and/or diet interventions relative to complete and ongoing interventions to identify gaps and needs for future lifestyle interventions in MM patients aimed at improving MM survivorship care. METHODS: This updated review was completed using a comprehensive search that was conducted using PubMed and ClinicalTrials.gov databases using keywords related to MM, exercise, physical activity, diet, nutrition and patient preferences. Studies involving adults diagnosed with MM were included. RESULTS: Among published studies, there are five exercise interventions and four diet and nutrition observational studies. The importance of individualized exercise interventions tailored to MM patients' needs was emphasized. Supervised exercise interventions showed higher adherence and engagement compared to unsupervised interventions. Observational diet/nutrition studies demonstrated that decreased gut microbiome diversity post-transplant is linked to poorer outcomes. Additionally, nutritional status and dietary patterns, such as high-carbohydrate and plant-based diets, can significantly impact clinical outcomes in MM patients, including sustained minimal residual disease negativity. Current clinical trials are primarily focused on feasibility and adherence, with a limited emphasis on long-term outcomes. In ClinicalTrials.gov, there are six ongoing exercise interventions, with an additional seven that are completed with no published results, one suspended trial and one active but not recruiting. Additionally, there are two combined diet and exercise interventions that are currently recruiting, with one active but no longer recruiting. Among diet and nutrition ongoing trials, there are currently two actively recruiting, two completed with no primary paper published and one study that was withdrawn. DISCUSSION: These findings underscore the need for more comprehensive, long-term and adequately powered studies on the impact of exercise and diet interventions in MM patients. Patient education and empowerment within these trials are crucial for enhancing engagement and adherence to these interventions.},
	doi = {10.3389/frhem.2025.1550681},
	pmid = {40970124},
	note = {PMC12442496}
}

@ARTICLE{10.7547/25-108,
	author = {Han P},
	title = {A Novel Diabetic Limb Preservation Initiative.},
	journal = {J Am Podiatr Med Assoc},
	year = {2025},
	abstract = {BACKGROUND: Diabetic foot ulcers (DFUs) and lower extremity amputations are major contributors to morbidity and mortality in individuals with diabetes. Among patients undergoing active cancer treatment, the risks are compounded by immunosuppression, peripheral neuropathy, and vascular complications. Even minor foot infections or wounds in these patients can necessitate the suspension of cancer therapy, with potentially life-threatening consequences. This study evaluated the impact of integrating symptom-focused patient education with coordinated podiatric care to reduce DFUs and amputations in this high-risk population with concurrent cancer and diabetes. METHODS: A five-year retrospective review was conducted at a National Cancer Institute (NCI)-designated comprehensive cancer center as part of the Novel Limb Preservation Initiative. The cohort included patients with Type II diabetes undergoing treatment for prostate, breast, colorectal, lymphoma, leukemia, thyroid, or lung cancers. Patients were assigned targeted educational modules based on self-reported diabetic foot symptoms. Podiatric care was individualized according to each patient's signs and symptoms, including routine diabetic foot examinations and close, timely monitoring when indicated. RESULTS: The intervention yielded a DFU incidence of 2.8% and an amputation rate of 0.43%, both lower than national benchmarks. Enhanced patient engagement through diabetic foot symptom-focused education and earlier detection of foot complications-including diabetic foot issues that may appear minor to laypersons-contributed to these improved outcomes. CONCLUSION: Integrating diabetic foot symptom-focused education with proactive podiatric monitoring significantly reduced DFUs and amputations in this high-risk population. This model, developed under the Novel Limb Preservation Initiative, offers a scalable strategy for broader implementation, particularly in high-risk communities, including Hispanic, African American, low socioeconomic, and rural populations across the United States.},
	doi = {10.7547/25-108},
	pmid = {40839533}
}

@ARTICLE{10.1159/000547426,
	author = {Munir T, Čiburienė E and Graklanov V and Gospodinova M, Jakšić O and Lipar L and Marton I, Panovská A, Petríková L and Pileckyte R and Pozsonyi Z and Slanina M, Škerget M and Bulj N},
	title = {Practical Management of Cardiovascular Adverse Events with BTKi Treatment in Patients with Chronic Lymphocytic Leukemia: A Consensus Report by Hematologists and Cardiologists.},
	journal = {Acta Haematol},
	year = {2025},
	abstract = {BACKGROUND: Cardiovascular (CV) adverse events (AEs), especially atrial fibrillation (AF) and hypertension, have been reported in patients receiving treatments for chronic lymphocytic leukemia (CLL), including Bruton's tyrosine kinase inhibitors (BTKis). Although these AEs are managed effectively in most cases and AE management guidelines exist, practical management approaches are inconsistent across regions and practices. We aimed to address these inconsistencies by developing consensus recommendations. SUMMARY: A European expert panel was assembled comprising eight hematologists and six cardiologists. Literature analysis, expert interviews, and the Delphi method were used to gain consensus on screening, monitoring, and treatment of AF and hypertension statements. KEY MESSAGES: Maintaining BTKi treatment is paramount to maximize time to next treatment; for patients at high risk of progression, this can be achieved by appropriately treating hypertension and AF and adjusting the BTKi dose. Patients should be risk-stratified as low, moderate, high, or very-high risk of cancer therapy-related CV toxicity and treated according to their disease status so that CLL treatment can be maintained. Patient education on symptom monitoring, home blood pressure monitoring, and electrocardiograms (baseline, every 3 months) are recommended to detect/monitor AF and hypertension. Close collaboration between hematologists and cardiologists is vital to achieve optimal patient outcomes.},
	doi = {10.1159/000547426},
	pmid = {40684756},
	note = {PMC12503664}
}

@ARTICLE{10.1007/s13187-025-02673-4,
	author = {Weiss JM and Mahayni Y and Steinberg AS},
	title = {Evaluation of Online Patient Education Materials for Acute Myeloid Leukemia.},
	journal = {J Cancer Educ},
	year = {2025},
	abstract = {In the modern healthcare landscape, many patients turn to online platforms for information about their diagnoses and treatment options. This study assessed 14 acute myeloid leukemia (AML) websites for their understandability and actionability using the Patient Education Materials Assessment Tool (PEMAT). Fourteen patient-facing US AML websites were searched in Google, selected, and analyzed using the PEMAT criteria. PEMAT is an online resource used to evaluate print materials, with two sections: understandability and actionability. Websites were rated by two independent reviewers, and discrepancies were discussed. Websites were categorized by government, public/private companies, patient advocacy groups, professional societies, and cancer centers. The study analyzed 14 websites on AML education material. The mean "understandability" score was 86% (range 77%-100%); government scored the highest, and private/public companies scored the lowest. The mean "actionability" score was 63% (range 33%-100%); patient advocacy groups scored the highest, and cancer centers scored the lowest. Most of the AML websites analyzed were easy to understand but lacked material that prompted patients to take action regarding their care. These actions included writing down common questions to ask their physician and inquiring about resources (e.g., support groups, relevant clinical trials, and financial support). This study highlights an opportunity to enhance online patient education material by improving understandability through content summaries and visual aids and improving actionability by adding tools (e.g., planners, checklists) to help patients take control of their disease management, including comprehending treatment options, understanding disease etiology, and managing financial assistance.},
	doi = {10.1007/s13187-025-02673-4},
	pmid = {40571896}
}

@ARTICLE{10.1007/s00520-025-09636-x,
	author = {Hung CW and Kuo MC and Chen SC},
	title = {Factors associated with physical and psychological health in non-Hodgkin's lymphoma patients: a prospective longitudinal study.},
	journal = {Support Care Cancer},
	year = {2025},
	abstract = {PURPOSE: Non-Hodgkins's lymphoma (NHL) patients' body mass index (BMI), information needs, and self-efficacy to manage illness vary over the course of treatment and are correlated to their physical and psychological health. The purpose of this study was to assess BMI, performance status, information needs, and self-efficacy to manage illness, and study their effects on symptom distress and anxiety in patients with NHL. METHODS: This prospective longitudinal study recruited NHL patients from a medical center in Northern Taiwan. A total of 47 NHL patients were followed before treatment (T0), at 6 weeks after beginning treatment (T1), and at 15 weeks after beginning treatment (T2). Generalized estimating equation analysis was used to examine the factors associated with symptom distress and anxiety. RESULTS: Self-efficacy to manage illness increased from T0 to T2 and was lowest at T0. Symptom distress slightly increased from T0 to T1 and then decreased at T2. Anxiety and information needs decreased from T0 to T2 and were highest at T0. Less symptom distress was associated with less anxiety, higher information needs, and higher self-efficacy to manage illness. Greater anxiety was associated with greater symptom distress, higher information needs, and less self-efficacy to manage illness. CONCLUSION: Information needs and self-efficacy to manage illness were important factors influencing symptom distress and anxiety in patients with NHL. Healthcare professionals should provide patient-centered education as part of pre-treatment care to facilitate self-care, empower self-efficacy to manage illness, and improve symptom distress and anxiety.},
	doi = {10.1007/s00520-025-09636-x},
	pmid = {40490567 [Indexed for MEDLINE]}
}

@ARTICLE{10.1007/s00520-025-09537-z,
	author = {Wen KY and Palmisiano N and Smith R and Slamon R and Keiffer G and Fidler C and Kasner M and Wilde L},
	title = {A smart pill bottle and text messaging intervention for promoting medication adherence in patients with chronic myeloid leukemia: a pilot study of txt4 TKI.},
	journal = {Support Care Cancer},
	year = {2025},
	abstract = {BACKGROUND: Patients undergoing tyrosine kinase inhibitor (TKI) therapy for chronic myeloid leukemia (CML) often face challenges with adherence, despite the efficacy of the treatment. Theory-guided and evidence-informed interventions addressing psychosocial and adherence barriers are critical for promoting adherence. Using a mixed-method approach, the pilot study developed and evaluated the feasibility and potential impact of an intervention "txt4TKI," to support medication and symptom management among CML patients undergoing TKI therapy. METHODS: Guided by the Necessity and Concerns framework, the study comprised two phases: Phase 1 involved qualitative patient needs assessment interviews informing intervention design. Phase 2 was a single-arm pilot study conducted for 6 months. The objectives of Phase 2 were to assess the feasibility and acceptability of the txt4 TKI intervention, examining enrollment and retention rates, intervention utilization, patient satisfaction, and changes in TKI medication adherence, psychosocial and symptom factors, from baseline to the 6-month follow-up. The intervention integrates a smart pill bottle activated with light, chimes to remind medication taking and three proactive text messages per week addressing clinical importance of TKI, symptom, lifestyle, and distress management as well as a biweekly toxicity assessment with tailored management feedback. Adherence was also objectively measured by the smart pill bottle and psychosocial survey was repeatedly assessed at 3- and 6-month. RESULTS: The intervention, developed iteratively and theoretically through patient-centered inputs (n = 10) and evidence-based information during Phase 1, integrates knowledge on CML, TKI therapy, self-care symptom management, emotional support, and healthy lifestyle recommendations. In Phase 2, 20 out of 30 eligible patients (67% consent rate), with a mean age of 55.3, 60% females and 65% Non-White participants, were enrolled. Fifty-five percent have been taking their medication for 1-3 years and 50% were taking Dasatinib. A high satisfaction and engagement rate of 90% with an 85% retention rate were observed. While medication self-efficacy significantly improved from baseline to 6 months, the adherence rate to TKI was slightly decreased over time. Post-intervention interviews indicated that participants found the intervention user-friendly, providing valuable information and emotional support, but adjusting the timing and content of interventions to tailor to different stages of therapy might better support sustained adherence. CONCLUSIONS: The txt4 TKI intervention using interactive text messaging and a smart pill bottle, feasible, and acceptable, demonstrated an increase in medication self-efficacy, an important aspect of medication adherence behaviors. Further research is needed to explore factors that influence the promotion and maintenance of adherence behaviors.},
	doi = {10.1007/s00520-025-09537-z},
	pmid = {40411655 [Indexed for MEDLINE]},
	note = {PMC12103477}
}

@ARTICLE{10.1016/j.ejon.2025.102896,
	author = {Hartono B and Bilodeau K},
	title = {Understanding post-treatment self-management learning needs of young adults diagnosed with hematological cancer: a qualitative study.},
	journal = {Eur J Oncol Nurs},
	year = {2025},
	abstract = {PURPOSE: To better support and promote an active role in survivorship, the purpose of this study was to identify and understand the perspective of young adults diagnosed with a hematological cancer in regard to their post-treatment self-management learning needs. METHOD: An interpretative-descriptive study was conducted. Semi-structured individual interviews were carried out with eight young adults (ages 18 to 29 at the end of active treatment), diagnosed with a leukemia or lymphoma, who have not received active treatment for at least one year. Iterative content analysis of interview data was performed. RESULTS: According to participants, it is when young adults experience transitions or feel alone in dealing with post-treatment challenges that they can identify a learning need. Protective factors and precipitating factors related to young adults, their entourage and their care providers (e.g., young adult characteristics, level of support, quality of patient education) can contribute to shape their view of self-management learning needs. For young adults, an underlying motivation guides the identification of attitudes (autonomy, responsibility, acceptance), knowledge (physical and psychosocial challenges, rights to accommodation for disability) or skills (self-assessment, action-planning, self-advocacy) to be gained. CONCLUSIONS: This study supports that young adults need more than information to feel confident in their ability to self-manage post-treatment challenges. Learning to self-manage is therefore a process of personal transformation, fueled by internal motivation, that also benefits from external support through collaboration between young adults, their entourage, and their care providers including oncology nurses.},
	doi = {10.1016/j.ejon.2025.102896},
	pmid = {40287998 [Indexed for MEDLINE]}
}

@ARTICLE{10.1111/jrh.70028,
	author = {Sheng J and Heiney SP and Wickersham KE and Nguyen LA and Harrison KW and Adams SA},
	title = {Living with chronic myelogenous leukemia in rural communities: Exploring factors related to tyrosine kinase inhibitors adherence with a mixed methods approach.},
	journal = {J Rural Health},
	year = {2025},
	abstract = {PURPOSE: Tyrosine kinase inhibitors (TKIs) improve chronic myeloid leukemia (CML) outcomes dramatically. However, limited research exists on patient-specific, medical, and psychosocial factors influencing TKI adherence. The purpose of the study was to better understand TKI adherence among rural CML patients, using a convergent parallel mixed-method design guided by the Information Motivation and Behavioral Skills Model. METHODS: Survivors with CML participated in semistructured interviews and completed self-reported questionnaires, including demographics, perceived stress, side effects, emotional support, and self-efficacy for managing chronic conditions. Qualitative and quantitative data were collected concurrently, analyzed separately, and then integrated. RESULTS: Sixteen participants aged 26 to 76 years completed the study. The duration of TKI therapy ranged from 0 to 12 years (mean ± standard deviation, 5.56 ± 4.08). While all reported adherence to TKI therapy, 31% held misconceptions about treatment duration, and 38% misunderstood reasons for blood tests prior to treatment or TKI refilled. Qualitative data yielded five major themes with descriptions of the shock of diagnosis, educational experiences regarding CML and its treatment, challenges in managing side effects and refills, the importance of social support, and strategies for maintaining remission and motivating adherence to TKI. CONCLUSIONS: This study describes the knowledge, motivations, challenges, and skills related to TKI adherence among rural patients with CML. A patient-centered approach is recommended for health care providers to improve adherence and enhance outcomes for CML patients on TKI therapy.},
	doi = {10.1111/jrh.70028},
	pmid = {40285411 [Indexed for MEDLINE]},
	note = {PMC12032516}
}

@ARTICLE{10.3390/vaccines13030284,
	author = {Morawska M and Masternak M, Grząśko N, Lech-Marańda E, Wróbel T and Giebel S and Tomasiewicz K and Giannopoulos K},
	title = {Awareness and Knowledge About Preventive Vaccinations Among Patients with Hematological Malignancies.},
	journal = {Vaccines (Basel)},
	year = {2025},
	abstract = {BACKGROUND: Patients with hematological malignancies, including multiple myeloma (MM) and chronic lymphocytic leukemia (CLL), are at an increased risk of severe infections due to both disease- and therapy-related immunosuppression. This cross-sectional study evaluated awareness of infection risks and vaccination uptake among 150 adults with various hematological malignancies from major Polish centers. METHODS: All participants completed a 30-item questionnaire capturing demographic data, treatment history, infection frequency, and vaccination attitude. Statistical analyses utilized Chi-square and Fisher's exact tests, with p < 0.05 considered statistically significant. RESULTS: Respondents had a median age of 57 years (range, 30-79), and 65.3% were female. MM was the most common diagnosis (64.7%), followed by CLL (4.0%) and other hematological malignancies (31.3%). Nearly all participants (99.3%) acknowledged their increased susceptibility to infections. Frequent infections (≥2 in the past 6 months) were significantly associated with transfusion dependency (p = 0.0001) and a history of hematopoietic stem cell transplantation (HSCT, p = 0.009). Although 69.3% expressed willingness to be vaccinated, 23.3% declined COVID-19 vaccination due to insufficient cancer-specific safety data. Higher education and urban residence correlated with greater acceptance of vaccines (p < 0.05). CONCLUSIONS: Our findings underscore the critical need for targeted educational strategies and robust vaccination guidelines in this immunocompromised population. Enhanced patient education and timely implementation of tailored vaccination regimens could reduce infection-related morbidity and improve the tolerability of cancer treatments.},
	doi = {10.3390/vaccines13030284},
	pmid = {40266134},
	note = {PMC11945929}
}

@ARTICLE{10.1097/NCC.0000000000001408,
	author = {Albrecht TA and Pastva AM and Yang Q and Lee Y and LeBlanc TW and Richardson DR and Leak Bryant A},
	title = {Pilot Testing of Build StaMINA: A Tailored Physical Activity Program for Adults Receiving Treatment for Acute Myeloid Leukemia.},
	journal = {Cancer Nurs},
	year = {2024},
	abstract = {BACKGROUND: Acute myeloid leukemia (AML) is an aggressive and often debilitating cancer for adults across the treatment trajectory. Patients experience frequent hospitalization, sedentariness, and negative sequelae including physical dysfunction and symptoms, which increase their risk for adverse events and mortality. OBJECTIVE: To test the preliminary efficacy of a tailored physical activity (PA) program. METHODS: This is a 2-group randomized controlled trial to explore the preliminary effects of a home-based tailored PA program versus attention control. The intervention includes PA across all physical domains important for independence. Assessments included physical function (6-Minute Walk Distance, primary), cognition (Montreal Cognitive Assessment), and patient-reported symptoms (Patient-Reported Outcomes Measurement Information System) at baseline and 6 and 12 weeks. RESULTS: Forty-six adults with AML were randomized into intervention (n = 22) and control (n = 24). Participants had a mean age of 58 years. No adverse events were reported. We observed a 22% attrition and 83% adherence to the intervention. Clinically significant increases in 6-Minute Walk Distance (mean, 49.78 ± 98.9 vs 3.7 ± 155.1 m) and mean scores for cognition (3.2 [9.9] vs -0.7 [9.7]), depression (-5.1 [12.9] vs -1.8 [7.7]), and self-efficacy (3.7 [8.0] vs 1.4 [7.2]) from baseline to 12 weeks were found in the intervention group versus control group. CONCLUSIONS: These findings support safety, feasibility, and further testing of this intervention in a larger trial powered to evaluate efficacy of this tailored PA intervention to support adult AML survivors during treatment. IMPLICATIONS FOR PRACTICE: This tailored intervention has the potential to support patients with AML and manage common sequelae across the treatment trajectory.},
	doi = {10.1097/NCC.0000000000001408},
	pmid = {40203204}
}

