@ARTICLE{10.3390/healthcare12232337,
	author = {Berardinelli D and Conti A and Hasnaoui A and Casabona E and Martin B and Campagna S and Dimonte V},
	title = {Nurse-Led Interventions for Improving Medication Adherence in Chronic Diseases: A Systematic Review.},
	journal = {Healthcare (Basel)},
	year = {2024},
	abstract = {Background: Poor medication adherence results in negative health outcomes and increased healthcare costs. Several healthcare professionals provide interventions to improve medication adherence, with the effectiveness of nurse-led interventions in people with chronic diseases remaining unclear. Objective: This study sought to evaluate the effectiveness of nurse-led interventions for improving medication adherence in adults with chronic conditions. Methods: Five databases (MEDLINE, CINAHL, EMBASE, Cochrane Library, SCOPUS) were searched without applying a temporal limit. Studies evaluating the effects of nurse-led interventions on medication adherence in adults with one or multiple chronic conditions were included. Interventions only targeting a single acute disease were excluded. Results: A total of twenty-two studies with 5975 participants were included. Statistically significant improvements in adherence were reported in five out of seven studies involving face-to-face visits to patients with heart failure (n = 2), chronic myeloid leukemia (n = 1), hypertension (n = 1) and multimorbidity (n = 1) and in four out of nine studies adopting a mixed method involving face-to-face visits and telephone follow-up for patients with heart failure (n = 1), hypertension (n = 1), coronary disease (n = 1) and multimorbidity (n = 1). Remote interventions were effective in improving medication adherence in one out of six studies. No statistically significant differences were found between tablet computer-based patient education and nurse-led educational sessions. The motivational approach was found to be one of the most common strategies used to promote patient medication adherence. Conclusions: Nurse-led face-to-face visits may be effective in improving medication adherence in people with chronic diseases. However, further research is needed because current methods for measuring medication adherence may not accurately capture patient behaviour and medication consumption patterns.},
	doi = {10.3390/healthcare12232337},
	pmid = {39684959},
	note = {PMC11641167}
}

@ARTICLE{10.1016/j.apjon.2024.100579,
	author = {Gupta A and Dagar G and Rehmani MU and Prasad CP and Saini D and Singh M and Shankar A},
	title = {CAR T-cell therapy in cancer: Integrating nursing perspectives for enhanced patient care.},
	journal = {Asia Pac J Oncol Nurs},
	year = {2024},
	abstract = {Chimeric antigen receptor (CAR) T-cell therapy represents a significant advancement in cancer treatment, particularly for hematologic malignancies. Various cancer immunotherapy strategies are presently being explored, including cytokines, cancer vaccines, immune checkpoint inhibitors, immunomodulators monoclonal antibodies, etc. The therapy has shown impressive efficacy in treating conditions such as acute lymphoblastic leukemia (ALL), diffuse large B-cell lymphoma (DLBCL), and multiple myeloma, often leading to complete remission in refractory cases. However, the clinical application of CAR T-cell therapy is accompanied by challenges, notably severe side effects. Effective management of these adverse effects requires meticulous monitoring and prompt intervention, highlighting the critical role of nursing in this therapeutic process. Nurses play a crucial role in patient education, monitoring, symptom management, care coordination, and psychosocial support, ensuring safe and effective treatment. As research advances and new CAR T-cell therapies are developed, the role of nursing professionals remains pivotal in optimizing patient outcomes. The continued evolution of CAR T-cell therapy promises improved outcomes, with nursing professionals integral to its success.},
	doi = {10.1016/j.apjon.2024.100579},
	pmid = {39315365},
	note = {PMC11417177}
}

@ARTICLE{10.1136/bmjopen-2024-084372,
	author = {Naumann K and Singh B and Bushaway S and Crane R and Deepak S and Hartland A and Konstantopoulos P and Mansell E and Marinelli V and Pallotta V and Tolfts A and Virieux A and Wall M and Wilksch S and Zhuang M and Atkinson M and Maher C},
	title = {Investigating the impact of multidisciplinary prehabilitation on deconditioning in patients eligible for haematopoietic allogenic stem cell transplantation: protocol for a feasibility trial.},
	journal = {BMJ Open},
	year = {2024},
	abstract = {BACKGROUND: Assessing multidisciplinary prehabilitation strategies becomes crucial to pre-emptively counter the physical, psychological and social negative impacts experienced during an allogenic haematopoietic stem cell transplant (allo-HSCT) among acute myeloid leukaemia (AML) and myelodysplastic syndrome (MDS) patients. Current evidence is restricted to studies during induction chemotherapy, omitting rehabilitation interventions and predominantly using exercise-only approaches without a multidisciplinary framework. The aim of this study is to investigate the feasibility, safety and preliminary efficacy of multidisciplinary prehabilitation in adults offered allo-HSCT. METHODS AND ANALYSIS: This 8-week single-group pre-post feasibility study aims to pilot a multidisciplinary prehabilitation intervention for participants undergoing allo-HSCT, with a focus on feasibility and safety. Participants, aged 18 or older, diagnosed with AML or MDS, and offered allo-HSCT, will be recruited between June 2023 and July 2024. The multidisciplinary prehabilitation intervention, conducted by the cancer allied health team at the Royal Adelaide Hospital, includes exercise physiology, physiotherapy, dietetics, social work, occupational therapy and psychology interventions. Consistent with a multidisciplinary treatment approach, each component is tailored to address different aspects of patient care, and adherence calculations will assess patient engagement and compliance. In addition, participants will continue to receive usual care from cancer allied health staff. The primary outcome of the study is to assess the feasibility of a multidisciplinary prehabilitation intervention by evaluating intervention uptake, retention, adherence, acceptability and safety. Secondary outcomes are leg strength, upper-body strength, aerobic fitness, falls risk, anthropometry, nutritional status, quality of life, anxiety, depression, self-efficacy for coping with cancer and distress. ETHICS AND DISSEMINATION: Ethics approval for this study has been provided by the Central Adelaide Local Health Network (HREC 2022/HRE00284). Recruitment for the study commenced in June 2023 and will continue until July 2024. The methods have been designed and are reported according to the SPIRIT and CONSORT-pilot study checklist. TRIAL REGISTRATION NUMBER: The Australian New Zealand Clinical Trials Registry (ANZCTR): ACTRN12623000052639.},
	doi = {10.1136/bmjopen-2024-084372},
	pmid = {39237275 [Indexed for MEDLINE]},
	note = {PMC11381652}
}

@ARTICLE{10.1007/s13187-024-02473-2,
	author = {Gabbard T and Perissinotti AJ and Benitez LL and Fraga M and Pettit KM and Bixby DL and Burke PW and Marini BL},
	title = {Impact of Chemotherapy Educational Videos for Patients with Acute Myeloid Leukemia.},
	journal = {J Cancer Educ},
	year = {2025},
	abstract = {Patient education in acute myeloid leukemia (AML) has become increasingly complex with the introduction of new treatments and chemotherapy regimens. Video education presents an opportunity to supplement traditional patient education and address some of the gaps associated with standard methods. This single-center study sought to assess the potential impact of supplemental video education on patients receiving induction chemotherapy for AML. Participants were consented to be randomized to receive their education with or without a supplemental video designed for their treatment regimen. We then provided a survey to each participant to assess knowledge retention, anxiety, and overall satisfaction with their care. Patients that received video education were found to have significantly improved knowledge retention compared to those that did not. There were no differences detected in anxiety or patient satisfaction. Video education appears to be an effective supplemental method for patient education in AML. Limitations include the single-center nature of the study at an urban academic medical center with a relatively well-educated, primarily Caucasian, younger population. Future research is warranted to assess the video in a diverse set of languages and to explore its broader benefits.},
	doi = {10.1007/s13187-024-02473-2},
	pmid = {38955941 [Indexed for MEDLINE]}
}

@ARTICLE{10.1159/000539756,
	author = {Marvin-Peek J and Shelton V and Brassil K and Fellman B and Barr A and Chien KS and Hammond D and Swaminathan M and Jain N and Wierda W and Ferrajoli A and DiNardo C},
	title = {Effect of Digital Health Coaching on Self-Efficacy and Patient-Reported Outcomes in Individuals with Acute Myeloid and Chronic Lymphocytic Leukemia: A Pilot Randomized Controlled Trial.},
	journal = {Acta Haematol},
	year = {2025},
	abstract = {INTRODUCTION: Promotion of self-efficacy can enhance engagement with health care and treatment adherence in patients with cancer. We report the outcomes of a pilot trial of a digital health coach intervention in patients with leukemia with the aim of improving self-efficacy. METHODS: Adult patients with newly diagnosed acute myeloid leukemia (AML) and chronic lymphocytic leukemia (CLL) were randomized 1:1 to a digital health coach intervention or standard of care. The primary outcome of self-efficacy was measured by the Cancer Behavior Inventory (CBI) score. RESULTS: A total of 147 patients (37 AML, 110 CLL) were enrolled from July 2020 to December 2022. In the AML cohort, there was a mean increase in CBI score of 7.03 in the digital health coaching arm compared to a mean decrease of -3.57 in the control arm at 30 days (p = 0.219). There were no significant associations between the intervention and other patient-reported outcomes for patients with CLL. CONCLUSION: There were numerical, but not statistically significant increases in self-efficacy metrics in AML patients who received digital health coaching. Although this trial was underpowered due to enrollment limitations during a pandemic, digital health coaching may provide benefit to patients with hematologic malignancy and warrants further investigation. INTRODUCTION: Promotion of self-efficacy can enhance engagement with health care and treatment adherence in patients with cancer. We report the outcomes of a pilot trial of a digital health coach intervention in patients with leukemia with the aim of improving self-efficacy. METHODS: Adult patients with newly diagnosed acute myeloid leukemia (AML) and chronic lymphocytic leukemia (CLL) were randomized 1:1 to a digital health coach intervention or standard of care. The primary outcome of self-efficacy was measured by the Cancer Behavior Inventory (CBI) score. RESULTS: A total of 147 patients (37 AML, 110 CLL) were enrolled from July 2020 to December 2022. In the AML cohort, there was a mean increase in CBI score of 7.03 in the digital health coaching arm compared to a mean decrease of -3.57 in the control arm at 30 days (p = 0.219). There were no significant associations between the intervention and other patient-reported outcomes for patients with CLL. CONCLUSION: There were numerical, but not statistically significant increases in self-efficacy metrics in AML patients who received digital health coaching. Although this trial was underpowered due to enrollment limitations during a pandemic, digital health coaching may provide benefit to patients with hematologic malignancy and warrants further investigation.},
	doi = {10.1159/000539756},
	pmid = {38861934 [Indexed for MEDLINE]},
	note = {PMC11632142}
}

