@ARTICLE{10.7759/cureus.58488,
	author = {Shin A and Banubakode S and Taveras Alam S and Gonzalez AO},
	title = {Evaluating the Readability of Online Blood Cancer Education Materials Across Different Readability Measures.},
	journal = {Cureus},
	year = {2024},
	abstract = {Introduction The National Institutes of Health and the American Medical Association recommend patient education materials (EMs) be at or below the sixth-grade reading level. The American Cancer Society, Leukemia & Lymphoma Society, and National Comprehensive Cancer Network have accurate blood cancer EMs. Methods One hundred one (101) blood cancer EMs from the above organizations were assessed using the following: Flesch Reading Ease Formula (FREF), Flesch-Kincaid Grade Level (FKGL), Gunning Fog Index (GFI), Simple Measure of Gobbledygook Index (SMOG), and the Coleman-Liau Index (CLI). Results Only 3.96% of patient EMs scored at or below the seventh-grade reading level in all modalities. Healthcare professional education materials (HPEMs) averaged around the college to graduate level. For leukemia and lymphoma patient EMs, there were significant differences for FKGL vs. SMOG, FKGL vs. GFI, FKGL vs. CLI, SMOG vs. CLI, and GFI vs. CLI. For HPEMs, there were significant differences for FKGL vs. GFI and GFI vs. CLI. Conclusion The majority of patient EMs were above the seventh-grade reading level. A lack of easily readable patient EMs could lead to a poor understanding of disease and, thus, adverse health outcomes. Overall, patient EMs should not replace physician counseling. Physicians must close the gaps in patients' understanding throughout their cancer treatment.},
	doi = {10.7759/cureus.58488},
	pmid = {38765438},
	note = {PMC11101262}
}

@ARTICLE{10.1136/bmjopen-2023-076321,
	author = {Saillard C and Cuvelier S and Villaron-Goetgheluck C and Boher JM and Almeida-Lopez L and Le Corroller AG and Denis P and Rivieccio C and Calvin S and Vey N and Bannier-Braticevic C},
	title = {Tripartite prehabilitation of patients with acute myeloid leukaemia and high-risk myelodysplastic syndromes during intensive chemotherapy before allogeneic haematopoietic stem cell transplantation (COHABILIT): protocol for an innovating prospective multicentre study.},
	journal = {BMJ Open},
	year = {2024},
	abstract = {OBJECTIVES: Acute myeloid leukaemia (AML) and high-risk myelodysplastic syndromes (MDS) are often treated with intensive chemotherapy followed by allogeneic haematopoietic stem cell transplantation (allo-HSCT). The pretransplant treatment results in a general deterioration of the patient's health and quality of life. Furthermore, allo-HSCT can be responsible for significant toxicity with risks of graft-versus-host disease (GvHD). Developing strategies to prevent physical deconditioning, undernutrition and psychological distress could help maintain a satisfactory general state of health before transplantation and thus limit these deleterious effects. This protocol evaluates the feasibility and adherence to a personalised prehabilitation programme, which can be modulated and assisted by connected objects, provided from the diagnosis to the allo-HSCT. METHODS AND ANALYSIS: This multicentre interventional study will include 50 patients treated for AML or high-risk MDS with intensive chemotherapy and eligible for allo-HSCT. The intervention consists of a coached, supervised or self-directed physical activity programme, organised during the hospitalisation phases and periods at home. At the same time, patients will receive a weekly dietary follow-up. The whole intervention is controlled and modulated through the use of a dedicated application and connected objects allowing adaptation and individualisation. The rate of participation in the prescribed physical activity sessions will assess the feasibility of this study. In addition, the evolution of physical capacities (Short Physical Performance Battery, grip and quadriceps strengths), psychosocial parameters (Functional Assessment of Cancer Therapy - Leukaemia, Functional Assessment of Cancer Therapy - Fatigue, subjective well-being, Hospital Anxiety and Depression Scale, self-efficacy, Coach-Athlete Relationship Questionnaire, interviews) and clinical status (weight, lean body mass, survival rate, number of infections, days of hospitalisation, GvHD) will be evaluated. ETHICS AND DISSEMINATION: The study procedures have been approved by the National Ethics Committee (21.00223.000003). Consent is given in person by each participant. The information collected on the participants contains only a non-identifiable study identifier. The results of this protocol will be published in a scientific paper and communicated to the medical staff of the medical centre. TRIAL REGISTRATION NUMBER: NCT03595787.},
	doi = {10.1136/bmjopen-2023-076321},
	pmid = {38553062 [Indexed for MEDLINE]},
	note = {PMC10982723}
}

@ARTICLE{10.1188/24.CJON.149-156,
	author = {Paredes C and Reed K and Moore L and Brant JM},
	title = {Perianal Injury Prevention in Patients With Leukemia.},
	journal = {Clin J Oncol Nurs},
	year = {2024},
	abstract = {BACKGROUND: Perianal injuries in adults with hematologic malignancies can result in sepsis or death. Patients on a 36-bed acute care oncology unit experienced increased perianal injuries from 2018 to 2021 based on a chart review, which revealed that 24 patients with leukemia, all of whom had received cytarabine, developed perianal injuries. OBJECTIVES: This study examined whether a nurse-led educational intervention would decrease perianal injuries. METHODS: A survey examined baseline nurse knowledge on perianal injuries. Nurses received a 10-minute in-service education session about perianal injuries, their predisposing factors, and prevention strategies followed by a survey to test their knowledge. Twenty nurses completed the pre- and postintervention surveys. FINDINGS: After the intervention, staff knowledge increased by 33%. One year postintervention, perianal injuries had decreased by more than 50%. Nurse and patient education are vital to decrease perianal injuries in patients with leukemia.},
	doi = {10.1188/24.CJON.149-156},
	pmid = {38511911 [Indexed for MEDLINE]}
}

@ARTICLE{10.7759/cureus.52120,
	author = {Aoyama T and Matsuoka M},
	title = {A Case of Successful Rehabilitation for Controlling Chronic Pain Following Osteonecrosis of the Femoral Head in a Young Adult Cancer Survivor.},
	journal = {Cureus},
	year = {2024},
	abstract = {A 26-year-old woman previously treated for acute lymphoblastic leukemia (ALL) 14 years ago faced challenges in managing chronic pain resulting from right femoral head necrosis, a complication of her earlier ALL treatment. Ultimately, the persistent chronic pain was successfully treated via a comprehensive rehabilitation approach. The patient presented with hip contractures, muscle weakness, and reduced endurance without evident arthropathic changes or inflammatory findings in the femoral head. Active physiotherapy was implemented with the primary objective of increasing her social activity. This therapeutic intervention effectively managed the severe pain without the necessity for analgesic drugs, leading to a significant improvement in the patient's social activity. Recognizing the adolescent and young adult age group as a critical phase of physical, psychological, and social development, cancer survivors within this age group require multimodal care. This study highlights the role of stepwise rehabilitation treatments involving stretching, muscle strengthening, and endurance training, particularly in challenging cases of chronic pain. Post-treatment interviews revealed that successful experiences in each movement contributed to increased self-efficacy and promoted not only the control of chronic pain but also fostered improvements in social activities.},
	doi = {10.7759/cureus.52120},
	pmid = {38344496},
	note = {PMC10858799}
}

@ARTICLE{10.1016/j.pec.2024.108177,
	author = {Rodenbach RA and Thordardottir T and Brauer M and Hall AC and Ward E and Smith CB and Campbell TC},
	title = {Balancing risks and rewards: How hematologists discuss uncertainty in allogeneic hematopoietic cell transplantation outcomes.},
	journal = {Patient Educ Couns},
	year = {2024},
	abstract = {OBJECTIVE: Allogeneic hematopoietic cell transplant (alloHCT) offers many patients with blood cancers a chance of cure but carries risks. We characterized how hematologists discuss the high-risk, high-reward concept of alloHCT. METHODS: Qualitative analysis of video-recorded virtual encounters of hematologists who routinely perform alloHCT with actors portraying an older man recently diagnosed with high-risk myelodysplastic syndrome. RESULTS: Hematologists (n = 37) were a median age of 44 years, 65% male, and 68% white. They frequently used "teeter-totter" language that juxtaposed alloHCT's risks and rewards in a dynamic, quickly alternating fashion and communicated uncertainty in transplant outcomes. This dialogue oscillated between encouragement about alloHCT's potential for cure and caution about its risks and occurred within single speech turns and in exchanges between hematologist and patient. Fewer hematologists outlined their big-picture stance on transplant's risks and benefits early in the conversation. Meanwhile, hematologists varied in how they counseled patients to manage transplant-related uncertainty and consider treatment decision making. CONCLUSION: Hematologists use "teeter-totter" language to express hope and concern, confidence and uncertainty, and encouragement and caution about the high-risk, high-reward nature of alloHCT. PRACTICE IMPLICATIONS: Teeter-totter language may help frame big-picture content about alloHCT's risks and benefits that is essential for patient education and decision making.},
	doi = {10.1016/j.pec.2024.108177},
	pmid = {38341898 [Indexed for MEDLINE]},
	note = {PMC10997451}
}

@ARTICLE{10.7759/cureus.49724,
	author = {Alanzi T and Almahdi R and Alghanim D and Almusmili L and Saleh A and Alanazi S and Alshobaki K and Attar R and Al Qunais A and Alzahrani H and Alshehri R and Sulail A and Alblwi A and Alanzi N and Alanzi N},
	title = {Factors Affecting the Adoption of Artificial Intelligence-Enabled Virtual Assistants for Leukemia Self-Management.},
	journal = {Cureus},
	year = {2023},
	abstract = {AIM AND PURPOSE: The purpose of this study is to analyze the various influencing factors affecting the adoption of artificial intelligence (AI)-enabled virtual assistants (VAs) for self-management of leukemia. METHODS: A cross-sectional survey design is adopted in this study. The questionnaire included eight factors (performance expectancy, effort expectancy, social influence, facilitating conditions, behavioral intention, trust, perceived privacy risk, and personal innovativeness) affecting the acceptance of AI-enabled virtual assistants. A total of 397 leukemia patients participated in the online survey. RESULTS: Performance expectancy (μ = 3.14), effort expectancy (μ = 3.05), and personal innovativeness (μ = 3.14) were identified to be the major influencing factors of AI adoption. Statistically significant differences (p < .05) were observed between the gender-based and age groups of the participants in relation to the various factors. In addition, perceived privacy risks were negatively correlated with all other factors. CONCLUSION: Although there are negative factors such as privacy risks and ethical issues in AI adoption, perceived effectiveness and ease of use among individuals are leading to greater adoption of AI-enabled VAs.},
	doi = {10.7759/cureus.49724},
	pmid = {38161825},
	note = {PMC10757561}
}

@ARTICLE{10.1111/tid.14197,
	author = {O'Keeffe JC and Singh N and Slavin MA},
	title = {Approach to diagnostic evaluation and prevention of invasive fungal disease in patients prior to allogeneic hematopoietic stem cell transplant.},
	journal = {Transpl Infect Dis},
	year = {2023},
	abstract = {In recent years, advancements in the treatment landscape for hematological malignancies, such as acute myeloid leukemia and acute lymphoblastic leukemia, have significantly improved disease prognosis and overall survival. However, the treatment landscape is changing and the emergence of targeted oral therapies and immune-based treatments has brought forth new challenges in evaluating and preventing invasive fungal diseases (IFDs). IFD disproportionately affects immunocompromised hosts, particularly those undergoing therapy for acute leukemia and allogeneic hematopoietic stem cell transplant. This review aims to provide a comprehensive overview of the pretransplant workup, identification, and prevention of IFD in patients with hematological malignancy. The pretransplant period offers a critical window to assess each patient's risk factors and implement appropriate prophylactic measures. Risk assessment includes evaluation of disease, host, prior treatments, and environmental factors, allowing a dynamic evaluation that considers disease progression and treatment course. Diagnostic screening, involving various biomarkers and radiological modalities, plays a crucial role in early detection of IFD. Antifungal prophylaxis choice is based on available evidence as well as individual risk assessment, potential for drug-drug interactions, toxicity, and patient adherence. Therapeutic drug monitoring ensures effective antifungal stewardship and optimal treatment. Patient education and counselling are vital in minimizing environmental exposures to fungal pathogens and promoting medication adherence. A well-structured and individualized approach, encompassing risk assessment, prophylaxis, surveillance, and patient education, is essential for effectively preventing IFD in hematological malignancies, ultimately leading to improved patient outcomes and overall survival.},
	doi = {10.1111/tid.14197},
	pmid = {37988269 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.ejon.2023.102455,
	author = {Rosenberg T and Kirkegaard J and Tveden MG and Hyldig N and Dieperink KB and Steffensen NH and Ulriksen SB and Lund T},
	title = {Making decisions for follow-up chemotherapy based on digital patient reported outcomes data in patients with multiple myeloma and other M protein diseases - A mixed method study.},
	journal = {Eur J Oncol Nurs},
	year = {2024},
	abstract = {OBJECTIVES: To test if Patient Reported Outcomes (PRO) data can replace physical on-site consultation in determining if patients with multiple myeloma, AL amyloidosis, or plasma cell leukemia are ready for their next bortezomib treatment without dose reduction. METHODS: We developed an online questionnaire addressing common side effects to bortezomib and an algorithm stratifying patients according to their responses and asked them to complete the questionnaire the day before attending the clinic. Applying a mixed-method study design of PRO data, time registrations, and interviews with patients and healthcare professionals, we tested the usability of electronic PRO data forming the basis of decision-making on whether patients are physically fit for the next treatment with an unchanged dose. RESULTS: The questionnaire and the associated algorithm were able to identify patients who were physically fit for treatment without need for further consultation, with a positive predictive value of 98 %. The method proved to be feasible for all groups of patients regardless of age and educational level. Patients and healthcare professionals found the online questionnaire to be advantageous and flexible. CONCLUSION: The use of PRO data to evaluate patients prior to bortezomib treatment is safe and feasible. Patients prefer to report their side effects themselves as it provides them with more freedom during their treatment.},
	doi = {10.1016/j.ejon.2023.102455},
	pmid = {37984313 [Indexed for MEDLINE]}
}

@ARTICLE{10.1182/bloodadvances.2023010879,
	author = {Tam C and Pinilla-Ibarz J and Castillo CG and Fenili AC and Huntley K and Karakus V and Mattar M and Miroli MA and Moura C and Pavlovsky M and Piotrowski F, Šimkovič M and Stilgenbauer S},
	title = {Results of VOICE: a global survey of disease-specific knowledge and perspectives of real-world patients with CLL.},
	journal = {Blood Adv},
	year = {2023},
	abstract = {The Virtual Opinions poll Independent Centered on CLL patients' Experience (VOICE) evaluated patients' knowledge about chronic lymphocytic leukemia (CLL), their perspectives on diagnosis and treatment, and their unmet needs. Clinicians and patient advocacy group representatives developed and distributed the survey from March through December 2022 in 12 countries, and 377 patients with ≥1 line of previous CLL treatment responded from Europe, Latin America, the United States, Australia, Egypt, and Turkey. A majority of them (90%; 336/374) relied on their physicians for information regarding CLL and treatment. If at high risk, respondents prefer oral medications to intravenous (78%; 232/296), fixed duration treatment over treatment until progression (69%; 185/270), outpatient over inpatient treatments (91%; 257/283). Over three-fourths of respondents (78%; 286/368) wanted to be involved in treatment decisions, but a minority actually participated (44%; 138/313). COVID-19 vaccinations were widely available (97%; 273/281), but one-fifth (19%; 63/331) were unaware that CLL increases vulnerability to infections. Most patients' physicians explained their treatment options (84%; 297/355), and 90% (271/301) understood their treatment. Notably, >10% would continue treatment normally if they experienced cardiac problems or arrhythmias, whereas 23% would consider stopping treatment if they developed skin cancer. Treatment-associated side effects affected 27% to 43% of patients. These results in a global patient population highlight gaps in patients' knowledge of risk groups, their susceptibility to infections including COVID, and the side effects of common treatments. Such knowledge can guide the appropriate targeting of patient education initiatives by clinicians, advocates, and policymakers.},
	doi = {10.1182/bloodadvances.2023010879},
	pmid = {37722356 [Indexed for MEDLINE]},
	note = {PMC10679812}
}

@ARTICLE{10.1016/j.cden.2023.05.016,
	author = {Mirfendereski P and France K},
	title = {A Patient Undergoing Treatment of Hematologic Malignancy Reports for Oral Evaluation.},
	journal = {Dent Clin North Am},
	year = {2023},
	abstract = {Oral lesions are commonly seen in patients with acute myeloid leukemia (AML) and may be the first clinical signs of disease. It is important for the dental provider to be able to recognize the oral manifestations of AML to allow for timely referral to a medical specialist. Patients with AML may receive treatment through chemotherapy, targeted drug therapies, or stem cell transplantation, which can involve oral complications and therefore necessitate case-specific patient education, dental evaluation, and treatment planning.},
	doi = {10.1016/j.cden.2023.05.016},
	pmid = {37714619 [Indexed for MEDLINE]}
}

@ARTICLE{10.2196/45259,
	author = {Verweij L and Metsemakers SJJPM and Ector GICG and Rademaker P and Bekker CL, van Vlijmen B, van der Reijden BA and Blijlevens NMA and Hermens RPMG},
	title = {Improvement, Implementation, and Evaluation of the CMyLife Digital Care Platform: Participatory Action Research Approach.},
	journal = {J Med Internet Res},
	year = {2023},
	abstract = {BACKGROUND: The evaluation of a continuously evolving eHealth tool in terms of improvement and implementation in daily practice is unclear. The CMyLife digital care platform provides patient-centered care by empowering patients with chronic myeloid leukemia, with a focus on making medication compliance insightful, discussable, and optimal, and achieving optimal control of the biomarker BCR-ABL1. OBJECTIVE: The aim of this study was to investigate to what extent the participatory action research approach is suitable for the improvement and scientific evaluation of eHealth innovations in daily clinical practice (measured by user experiences) combined with the promotion of patient empowerment. METHODS: The study used iterative cycles of planning, action, and reflection, whereby participants' experiences (patients, health care providers, the CMyLife team, and app suppliers) with the platform determined next actions. Co-design workshops were the foundation of this cyclic process. Moreover, patients filled in 2 sets of questionnaires for assessing experiences with CMyLife, the actual use of the platform, and the influence of the platform after 3 and at least 6 months. Data collected during the workshops were analyzed using content analysis, which is often used for making a practical guide to action. Descriptive statistics were used to characterize the study population in terms of information related to chronic myeloid leukemia and sociodemographics, and to describe experiences with the CMyLife digital care platform and the actual use of this platform. RESULTS: The co-design workshops provided insights that contributed to the improvement, implementation, and evaluation of CMyLife and empowered patients with chronic myeloid leukemia (for example, simplification of language, and improvement of the user friendliness of functionalities). The results of the questionnaires indicated that (1) the platform improved information provision on chronic myeloid leukemia in 67% (33/49) of patients, (2) the use of the medication app improved medication compliance in 42% (16/38) of patients, (3) the use of the guideline app improved guideline adherence in 44% (11/25) of patients, and (4) the use of the platform caused patients to feel more empowered. CONCLUSIONS: A participatory action research approach is suited to scientifically evaluate digital care platforms in daily clinical practice in terms of improvement, implementation, and patient empowerment. Systematic iterative evaluation of users' needs and wishes is needed to keep care centered on patients and keep the innovation up-to-date and valuable for users.},
	doi = {10.2196/45259},
	pmid = {37713242 [Indexed for MEDLINE]},
	note = {PMC10541637}
}

@ARTICLE{10.1177/15347354231191984,
	author = {Klobodu C and Deutsch J and Vitolins MZ and Fisher K and Nasser JA and Stott D and Milliron BJ},
	title = {Optimizing Fertility Treatment With Nutrition Guidance: Exploring Barriers and Facilitators to Healthful Nutrition Among Female Cancer Survivors With Fertility Challenges.},
	journal = {Integr Cancer Ther},
	year = {2023},
	abstract = {INTRODUCTION: Young women diagnosed with cancer are at an increased risk for infertility compared to women without a cancer diagnosis. Consuming a healthful diet comprised of whole grains, fruits, vegetables, and unsaturated fats has been found to improve both fertility and cancer survivorship. Given this reason, dietary interventions tailored to support female cancer survivors with fertility challenges are of immense importance. Therefore, the aim of this study was to explore barriers and facilitators to healthful nutrition among female cancer survivors with fertility challenges, to inform the development of dietary interventions for this population. METHODS: Using a formative research design, interview, survey, and dietary intake data were collected from 20 female cancer survivors of reproductive age. Participant-check focus group discussions were conducted to validate findings. All interviews were recorded and transcribed verbatim. Transcripts were coded and analyzed using a thematic analysis approach. Quantitative data were analyzed using means, standard deviations, ranges, frequencies, and percentages. RESULTS: The average age of respondents was 31.47 ± 3.5 years and the average BMI was 24.78 ± 4.1 kg/m2. All participants were college educated, 45% identified as White, 50% as Black, and 10% as Hispanic or Latinx. Cancer diagnoses included breast, thyroid, ovarian, leukemia, and gastrointestinal cancers. The following themes were identified: (1) Lack of nutrition-related resources and detailed guidance, (2) Work-life balance, (3) Perceived rigidity of dietary guidance, (4) Treatment-related fatigue, (5) Having trust in healthcare providers, (6) Higher motivation to change nutrition behavior, and (7) Recognizing the additional benefits of nutrition. CONCLUSION: These findings indicate a sought-after yet unmet need for post-cancer treatment fertility nutrition recommendations. Interventions should be tailored to women's needs and focus on improving their self-efficacy to make healthful dietary choices.},
	doi = {10.1177/15347354231191984},
	pmid = {37559460 [Indexed for MEDLINE]},
	note = {PMC10416655}
}

@ARTICLE{10.5414/CP204275,
	author = {Nouha T and Asma M and Nadia B and Emna BM and Yosra Z and Yosra S},
	title = {Acute myeloid leukemia after 10 years of azathioprine treatment for Crohn's disease.},
	journal = {Int J Clin Pharmacol Ther},
	year = {2023},
	abstract = {BACKGROUND: Azathioprine, which is an immunosuppressive agent commonly used for chronic inflammatory bowel disease, may be associated with an increased risk of certain cancers such as hematologic malignancies. CASE REPORT: A 50-year-old man with a 27-year history of Crohn's disease had been under azathioprine treatment at a dose of 2.5 mg/kg/day (150 mg/day) since 2007, after ileocecal resection to avoid postoperative recurrences. Ten years later, the patient presented with a 3-week history of worsening general condition and fever. The physical examination revealed skin paleness and fever. The biological assessment showed pancytopenia. Hematological toxicity of azathioprine was suspected. The drug was immediately stopped. A bone marrow biopsy with immunophenotyping studies confirmed the diagnosis of acute myeloid leukemia. Chemotherapy was indicated but the patient passed away 2 weeks later. CONCLUSION: Azathioprine may be implicated in therapy-related acute myeloid leukemia. Close monitoring of its hematological toxicity, as well as patient education to adhere to this monitoring program, are crucial to detect this life-threatening complication.},
	doi = {10.5414/CP204275},
	pmid = {37548454 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.pec.2023.107883,
	author = {Grauman Å and Kontro M and Haller K and Nier S and Aakko S and Lang K and Zingaretti C and Meggiolaro E and De Padova S and Marconi G and Martinelli G and Heckman CA and Simonetti G and Bullinger L and Kihlbom U},
	title = {Personalizing precision medicine: Patients with AML perceptions about treatment decisions.},
	journal = {Patient Educ Couns},
	year = {2023},
	abstract = {BACKGROUND: This study aims to explore patients' with acute myeloid leukemia perceptions about precision medicine and their preferences for involvement in this new area of shared decision-making. METHODS: Individual semi-structured interviews were conducted in Finland, Italy and Germany (n = 16). The study population included patients aged 24-79 years. Interviews were analyzed with thematic content analysis. RESULTS: Patient's perceived lack of knowledge as a barrier for their involvement in decision-making. Treatment decisions were often made rapidly based on the patient's intuition and trust for the physician rather than on information, in situations that decrease the patient's decision capacity. The patients emphasized that they are in a desperate situation that makes them willing to accept treatment with low probabilities of being cured. CONCLUSIONS: The study raised important issues regarding patients' understanding of precision medicine and challenges concerning how to involve patients in medical decision-making. Although technical advances were viewed positively, the role of the physician as an expert and person-of-trust cannot be replaced. PRACTICE IMPLICATIONS: Regardless of patients' preferences for involvement in decision-making, information plays a crucial role for patients' perceived involvement in their care. The concepts related to precision medicine are complex and will imply challenges to patient education.},
	doi = {10.1016/j.pec.2023.107883},
	pmid = {37421687 [Indexed for MEDLINE]}
}

@ARTICLE{10.2196/44533,
	author = {LeBlanc MR and LeBlanc TW and Yang Q and McLaughlin J and Irish K and Smith SK},
	title = {A Mobile App to Support Self-Management in Patients with Multiple Myeloma or Chronic Lymphocytic Leukemia: Pilot Randomized Controlled Trial.},
	journal = {JMIR Cancer},
	year = {2023},
	abstract = {BACKGROUND: Patients with blood cancer experience serious physical and emotional symptoms throughout their cancer journey. OBJECTIVE: Building on previous work, we aimed to develop an app designed to help patients with multiple myeloma and chronic lymphocytic leukemia self-manage symptoms and test it for acceptability and preliminary efficacy. METHODS: We developed our Blood Cancer Coach app with input from clinicians and patients. Our 2-armed randomized controlled pilot trial recruited participants from Duke Health and nationally in partnerships with the Association of Oncology Social Work, Leukemia and Lymphoma Society, and other patient groups. Participants were randomized to the attention control (Springboard Beyond Cancer website) arm or the Blood Cancer Coach app intervention arm. The fully automated Blood Cancer Coach app included symptom and distress tracking with tailored feedback, medication reminders and adherence tracking, multiple myeloma and chronic lymphocytic leukemia education resources, and mindfulness activities. Patient-reported data were collected at baseline, 4 weeks, and 8 weeks for both arms through the Blood Cancer Coach app. Outcomes of interest were global health (Patient Reported Outcomes Measurement Information System Global Health), posttraumatic stress (Posttraumatic Stress Disorder Checklist for DSM-5), and cancer symptoms (Edmonton Symptom Assessment System Revised). Among participants in the intervention arm, satisfaction surveys and usage data were used to evaluate acceptability. RESULTS: Among 180 patients who downloaded the app, 49% (89) of them consented to participate and 40% (72) of them completed baseline surveys. Of those who completed baseline surveys, 53% (38) of them completed week 4 surveys (16 intervention and 22 control) and 39% (28) of them completed week 8 surveys (13 intervention and 15 control). Most participants found the app at least moderately effective at helping manage symptoms (87%), feeling more comfortable seeking help (87%), increasing awareness of resources (73%), and reported being satisfied with the app overall (73%). Participants completed an average of 248.5 app tasks over the 8-week study period. The most used functions within the app were medication log, distress tracking, guided meditations, and symptom tracking. There were no significant differences between the control and intervention arms at week 4 or 8 on any outcomes. We also saw no significant improvement over time within the intervention arm. CONCLUSIONS: The results of our feasibility pilot were promising in which most participants found the app to be helpful in managing their symptoms, reported satisfaction with the app, and that it was helpful in several important areas. We did not, however, find significantly reduced symptoms or improved global mental and physical health over 2 months. Recruitment and retention were challenging for this app-based study, an experience echoed by others. Limitations included a predominantly White and college educated sample. Future studies would do well to include self-efficacy outcomes, target those with more symptoms, and emphasize diversity in recruitment and retention. TRIAL REGISTRATION: ClinicalTrials.gov NCT05928156; https://clinicaltrials.gov/study/NCT05928156.},
	doi = {10.2196/44533},
	pmid = {37410541},
	note = {PMC10360008}
}

@ARTICLE{10.14715/cmb/2023.69.3.13,
	author = {Xue Wang and Hongyue Yang and Xiaoling Zhang and Qi Fan},
	title = {The effect of nursing intervention on self-care self-efficacy and genes related to anxiety in patients with bone marrow transplantation.},
	journal = {Cell Mol Biol (Noisy-le-grand)},
	year = {2023},
	abstract = {Leukemia patients, after bone marrow transplantation, face many problems that hurt their self-efficacy in self-care. The present study aimed to determine the effect of health promotion strategies on the self-efficacy of patients undergoing bone marrow transplantation in self-care. The expression level of two genes affecting anxiety (i.e., 5-hydroxytryptamine receptor 1A (5-HT1A) and Corticotropin Releasing Hormone Receptor 1 (CRHR1)) was also investigated. For this purpose, this semi-experimental study was conducted before and after in bone marrow transplant candidate patients. Sixty patients were randomly divided into test and control groups. The test group received training on health promotion strategies, and the control group was treated according to the department's routine. Then the self-efficacy of the two groups was compared before and thirty days after the intervention. Also, the expression level of two genes was done by real-time PCR. Data analysis was done using descriptive statistics and paired t-tests, independent t-tests, analysis of covariance, and chi-square in SPSS 11.5 software. The results showed that there was no significant difference between the demographic variables of the two groups. The self-efficacy of the test group in the general scale and dimensions of adaptability, decision-making, and stress reduction increased compared to the control group and themselves before the training (p>0.001). The difference in self-efficacy scores in all dimensions before the intervention was statistically significant (p<0.05). The genetic evaluations also confirmed the obtained results. According to the expression of 5-HT1A and CRHR1 genes, the level of these genes which directly relate to anxiety were significantly decreased after intervention in the test group. In general, teaching health promotion strategies to bone marrow transplant patients can increase the confidence of these patients in taking care of themselves in the treatment process, which will ultimately lead to more survival and a higher quality of life in these patients.},
	doi = {10.14715/cmb/2023.69.3.13},
	pmid = {37300683 [Indexed for MEDLINE]}
}

@ARTICLE{10.1371/journal.pone.0285420,
	author = {Tam S and Kumar R and Lopez P and Mattsson J and Alibhai S and Atenafu EG and Bernstein LJ and Chang E and Clarke S and Langelier D and Lipton J and Mayo S and Papadakos T and Jones JM},
	title = {A longitudinal multidimensional rehabilitation program for patients undergoing allogeneic blood and marrow transplantation (CaRE-4-alloBMT): Protocol for a phase II feasibility pilot randomized controlled trial.},
	journal = {PLoS One},
	year = {2023},
	abstract = {BACKGROUND: Allogeneic blood and marrow transplantation (alloBMT) is a curative treatment for blood cancers associated with various treatment-related adverse events and morbidities. Current rehabilitation programs are limited for patients undergoing alloBMT and research is urgently needed to test the acceptability and effectiveness of these programs. In response, we developed a 6-month multidimensional longitudinal rehabilitation program that spans from pre transplant to 3 months post transplant discharge (CaRE-4-alloBMT). METHODS: This study is a phase II randomized controlled trial (RCT) conducted at the Princess Margaret Cancer Centre in patients undergoing alloBMT. A total of 80 patients stratified by frailty score will be randomized to receive usual care (n = 40) or CaRE-4-alloBMT plus usual care (n = 40). The CaRE-4-alloBMT program includes individualized exercise prescriptions, access to online education through a dedicated self-management platform, wearable technology for remote monitoring, and remote tailored clinical support. Feasibility will be assessed by examining the recruitment and retention rates and adherence to the intervention. Safety events will be monitored. Acceptability of the intervention will be assessed through qualitative interviews. Secondary clinical outcomes will be collected through questionnaires and physiological assessments at baseline (T0, 2-6 weeks pre-transplant), transplant hospital admission (T1), hospital discharge (T2), and 3 months post-discharge (T3). CONCLUSION: This pilot RCT study will determine the feasibility and acceptability of the intervention and study design and will inform full-scale RCT planning.},
	doi = {10.1371/journal.pone.0285420},
	pmid = {37192195 [Indexed for MEDLINE]},
	note = {PMC10187908}
}

@ARTICLE{10.1007/s11764-023-01370-9,
	author = {Nabulsi NA and Nazari JL and Lee TA and Patel PR and Sweiss KI and Le T and Sharp LK},
	title = {Perceptions of prescription opioids among marginalized patients with hematologic malignancies in the context of the opioid epidemic: a qualitative study.},
	journal = {J Cancer Surviv},
	year = {2024},
	abstract = {PURPOSE: Opioids are essential for treating pain in hematologic malignancies (HM), yet are heavily stigmatized in the era of the opioid epidemic. Stigma and negative attitudes towards opioids may contribute to poorly managed cancer pain. We aimed to understand patient attitudes towards opioids for HM pain management, particularly among historically marginalized populations. METHODS: We interviewed a convenience sample of 20 adult patients with HM during outpatient visits at an urban academic medical center. Semi-structured interviews were audio-recorded, transcribed, and qualitatively analyzed using the framework method. RESULTS: Among 20 participants, 12 were female and half were Black. Median age was 62 (interquartile range = 54-68). HM diagnoses included multiple myeloma (n = 10), leukemia (n = 5), lymphoma (n = 4), and myelofibrosis (n = 1). Eight themes emerged from interviews that seemed to influence HM-related pain self-management, including (1) fear of opioid-related harms, (2) opioid side effects and harms to health, (3) fatalism and stoicism, (4) perceived value of opioids for HM-related pain, (5) low perceived susceptibility to opioid-related harms and externalizing blame, (6) preferences for non-opioid pain management approaches, (7) trust in providers and opioid accessibility, and (8) external sources of pain management support and information. CONCLUSIONS: This qualitative study demonstrates that fears and stigmatized views of opioids can conflict with marginalized patients' needs to manage debilitating HM-related pain. Negative attitudes towards opioids were shaped by the opioid epidemic and reduced willingness to seek out or use analgesics. IMPLICATIONS FOR CANCER SURVIVORS: These findings help expose patient-level barriers to optimal HM pain management, revealing attitudes, and knowledge to be targeted by future pain management interventions in HM.},
	doi = {10.1007/s11764-023-01370-9},
	pmid = {37022642 [Indexed for MEDLINE]}
}

