@ARTICLE{10.1186/s12913-023-09153-9,
	author = {Verweij L and Ector GICG and Smit Y, van Vlijmen B, van der Reijden BA and Hermens RPMG and Blijlevens NMA},
	title = {Effectiveness of digital care platform CMyLife for patients with chronic myeloid leukemia: results of a patient-preference trial.},
	journal = {BMC Health Serv Res},
	year = {2023},
	abstract = {BACKGROUND: Two most important factors determining treatment success in chronic myeloid leukemia (CML) are adequate medication compliance and molecular monitoring albeit still being suboptimal. The CMyLife platform is an eHealth innovation, co-created with and for CML patients, aiming to improve their care, leading to an increased quality of life and the opportunity of hospital-free care. OBJECTIVE: To explore the effectiveness of CMyLife in terms of information provision, patient empowerment, medication compliance, molecular monitoring, and quality of life. METHODS: Effectiveness of CMyLife was explored using a patient-preference trial. Upon completion of the baseline questionnaire, participants actively used (intervention group) or did not actively use (questionnaire group) the CMyLife platform for at least 6 months, after which they completed the post-intervention questionnaire. Scores between the intervention group and the questionnaire group were compared with regard to the within-subject change between baseline and post-measurement using Generalized Estimating Equation models. RESULTS: At baseline, 33 patients were enrolled in the questionnaire group and 75 in the intervention group. Online health information knowledge improved significantly when actively using CMyLife and patients felt more empowered. No significant improvements were found regarding medication compliance and molecular monitoring, which were already outstanding. Self-reported effectiveness showed that patients experienced that using CMyLife improved their medication compliance and helped them to oversee their molecular monitoring. Patients using CMyLife reported more symptoms but were better able to manage these. CONCLUSIONS: Since hospital-free care has shown to be feasible in time of the COVID-19 pandemic, eHealth-based innovations such as CMyLife could be a solution to maintain the quality of care and make current oncological health care services more sustainable. TRIAL REGISTRATION: ClinicalTrials.gov NCT04595955 , 22/10/2020.},
	doi = {10.1186/s12913-023-09153-9},
	pmid = {36890512 [Indexed for MEDLINE]},
	note = {PMC9994406}
}

@ARTICLE{10.1002/cncr.34645,
	author = {El-Jawahri A and Luskin MR and Greer JA and Traeger L and Lavoie M and Vaughn DM and Andrews S and Yang D and Boateng KY and Newcomb RA and Ufere NN and Fathi AT and Hobbs G and Brunner A and Abel GA and Stone RM and DeAngelo DJ and Wadleigh M and Temel JS},
	title = {Psychological mobile app for patients with acute myeloid leukemia: A pilot randomized clinical trial.},
	journal = {Cancer},
	year = {2023},
	abstract = {BACKGROUND: Patients with acute myeloid leukemia (AML) experience a substantial decline in quality of life (QoL) and mood during their hospitalization for intensive chemotherapy, yet few interventions have been developed to enhance patient-reported outcomes during treatment. METHODS: We conducted a pilot randomized trial (ClinicalTrials.gov identifier NCT03372291) of DREAMLAND, a psychological mobile application for patients with a new diagnosis of AML who are receiving intensive chemotherapy. Patients were randomly assigned to DREAMLAND or usual care. DREAMLAND included four required modules focused on: (1) supportive psychotherapy to help patients deal with the initial shock of diagnosis, (2) psychoeducation to manage illness expectations, (3) psychosocial skill-building to promote effective coping, and (4) self-care. The primary end point was feasibility, which was defined as ≥60% of eligible patients enrolling and 60% of those enrolled completing ≥60% of the required modules. We assessed patient QoL (the Functional Assessment of Cancer Therapy-Leukemia), psychological distress (the Hospital Anxiety and Depression Scale and the Patient Health Questionnaire-9), symptom burden (the Edmonton Symptom Assessment Scale), and self-efficacy (the Cancer Self-Efficacy Scale) at baseline and at day 20 after postchemotherapy. RESULTS: We enrolled 60 of 90 eligible patients (66.7%), and 62.1% completed ≥75% of the intervention modules. At day 20 after chemotherapy, patients who were randomized to DREAMLAND reported improved QoL scores (132.06 vs. 110.72; p =.001), lower anxiety symptoms (3.54 vs. 5.64; p = .010) and depression symptoms (Hospital Anxiety and Depression Scale: 4.76 vs. 6.29; p = .121; Patient Health Questionnaire-9: 4.62 vs. 8.35; p < .001), and improved symptom burden (24.89 vs. 40.60; p = .007) and self-efficacy (151.84 vs. 135.43; p = .004) compared with the usual care group. CONCLUSIONS: A psychological mobile application for patients with newly diagnosed AML is feasible to integrate during hospitalization for intensive chemotherapy and may improve QoL, mood, symptom burden, and self-efficacy.},
	doi = {10.1002/cncr.34645},
	pmid = {36655338 [Indexed for MEDLINE]}
}

@ARTICLE{10.1007/s00520-022-07530-4,
	author = {Accogli MA and Denti M and Costi S and Fugazzaro S},
	title = {Therapeutic education and physical activity are feasible and safe in hematologic cancer patients referred to chemotherapy: results of a randomized controlled trial.},
	journal = {Support Care Cancer},
	year = {2022},
	abstract = {PURPOSE: Although over 60% of patients with hematologic cancer report distressing fatigue, they often do not receive recommendations on fatigue management strategies. The aim of this pilot study was to estimate the feasibility of therapeutic education and physical activity (TEPA) by measuring the patients' adherence to this multidimensional intervention. The secondary aim was to estimate the impact of TEPA on clinical outcomes. METHODS: Patients with hematologic cancer participated in this single-center, open-label, randomized controlled trial. The control group (CG) received two educational group sessions on fatigue and physical activity. The experimental group (EG) received the two educational sessions plus six weekly individual sessions aimed at implementing a personalized physical exercise program. Follow-ups were at 1, 3, and 7 months. RESULTS: Forty-six patients referred to chemotherapy were included, corresponding to 54% of recruitment rate. Adherence reached 90% in the EG and 68% in the CG. Most patients (65% in EG and 64% in CG) attended a minimum of 80% of the planned sessions. Overall retention rate was 87% (85% in EG and 91% in CG). No adverse events were registered. No between-group differences were detected in fatigue (FACIT-F), psychological distress (NCCN Distress Thermometer), QoL (EORTC QLQ-C30), or functional exercise capacity (TUG test and 6MWT). Adherence to an active lifestyle, measured by a semi-structured interview, increased from 56.5 to 84% in the EG at 7 months (p = 0.02), whereas it decreased slightly in the CG (from 47.8 to 42.9%). CONCLUSION: Multidimensional rehabilitation interventions are feasible and safe in this population, and larger trials should focus on the efficacy of such approaches on clinically relevant outcomes. TRIAL REGISTRATION: ClinicalTrials.gov Identifier: NCT03403075.},
	doi = {10.1007/s00520-022-07530-4},
	pmid = {36534365 [Indexed for MEDLINE]},
	note = {PMC9763142}
}

@ARTICLE{10.2147/PPA.S369628,
	author = {Higuita-Gutiérrez LF and Estrada-Mesa DA and Cardona-Arias JA},
	title = {Healthcare Inequities Experienced by Patients with Cancer: A Qualitative Study in Medellín, Colombia.},
	journal = {Patient Prefer Adherence},
	year = {2022},
	abstract = {PURPOSE: This study aimed to understand the lived experiences of patients with cancer that facing inequities in oncological care in the city of Medellín. PATIENTS AND METHODS: A qualitative study was conducted based on the theoretical and methodological elements of the grounded theory, specifically the description and conceptual ordering of Corbin and Strauss. Sixteen patients with cancer, who belonged to low (n=5), middle (n=4) and high (n=7) social classes, were included by theoretical sampling with category saturation. Data were collected using semi-structured interviews and analyzed in a category system based on the three social classes. RESULTS: The patients were aged between 23 and 71 years old, and they were diagnosed with different types of cancer such as breast, cervical, prostate, stomach, leukemia and lymphoma. Patients' experiences showed that diagnosis, specialized care, treatment and hospital discharge were different based on their social class. CONCLUSION: Patients' lived experiences associated with cancer reflect complex social situations, in which social determinants affect the level of citizens' empowerment and self-management against the risks of get disease and die. Being part of low and middle social classes meant being subjected to a dehumanized, cold, impersonal and discontinuous treatment, in which healthcare was focused on the disease instead of individuals' preferences and values. In contrast, patients belonging to the high class had the resources necessary to face risks, which ensured access to more humanized and individualized healthcare.},
	doi = {10.2147/PPA.S369628},
	pmid = {35958886},
	note = {PMC9362511}
}

@ARTICLE{10.1177/10781552221090904,
	author = {Khadam S and Chu T and Deekes N and FitzGerald D and Preston A and Duncan N},
	title = {An investigation of the use of app technology to support clinical management of patients with chronic myeloid leukaemia (CML).},
	journal = {J Oncol Pharm Pract},
	year = {2023},
	abstract = {INTRODUCTION: The availability of healthcare apps to support patient self-management of various medical conditions, including cancer, has increased considerably in the past decade. However, there are limited published data on the role of apps in the management of chronic myeloid leukaemia (CML). The primary aim of this study was to investigate the current and future role of apps as a means of supporting patients with CML. METHODS: A 31-item questionnaire was developed and distributed to patients via three on-line CML support groups. RESULTS: Responses were received from 286 patients. There was an approximate 2:1 female: male split and the majority (54%, n = 155) resided in the United Kingdom. 91% (n = 260) of respondents were currently receiving drug treatment for their CML. 23.4% (n = 67) of respondents were aware that apps were available to support their CML management and 11.5% (n = 33) had experience of using such an app. 94.1% (n = 238) of those who had not used a patient support app in the past stated that they would consider using an app in the future to help manage their disease. App awareness was significantly higher amongst male patients (30.3% vs. 19.9%). Likelihood of being a current or previous app user was higher amongst younger patients (16.3% for <55 years old vs. 5.6% for ≥55 years old) whilst younger patients and those with a more recent diagnosis of CML were both more likely to be interested in using an app in the future. When asked about potential app functionality, a drug interaction checker was the feature of greatest interest to respondents. CONCLUSIONS: We have identified both a lack of awareness of and a low uptake of patient support apps amongst CML patients. Importantly, we have demonstrated a clear interest in CML-specific apps amongst this population. Based on the functionality that study participants were most interested in, we will work with health care professionals, app developers and patients to develop a new app to deliver holistic support to CML patients.},
	doi = {10.1177/10781552221090904},
	pmid = {35404173 [Indexed for MEDLINE]},
	note = {PMC10302356}
}

@ARTICLE{10.1016/j.jval.2022.01.023,
	author = {Wujcik D and Dudley WN and Dudley M and Gupta V and Brant J},
	title = {Electronic Patient Symptom Management Program to Support Patients Receiving Cancer Treatment at Home During the COVID-19 Pandemic.},
	journal = {Value Health},
	year = {2022},
	abstract = {OBJECTIVES: Remote patient monitoring became critical for patients receiving cancer treatment during the COVID-19 pandemic. We sought to test feasibility of an electronic patient symptom management program implemented during a pandemic. We collected and analyzed the real-world data to inform practice quality improvement and understand the patient experience. METHODS: Eligible patients had breast, lung, or ovarian cancers, multiple myeloma, or acute myeloid leukemia and 12 weeks of planned chemotherapy. Patients were notified that a symptom survey with common symptoms derived from the National Cancer Institute's Patient-Reported Outcomes Version of the Common Terminology Criteria for Adverse Events was available to complete using a smart phone, tablet, or computer. Patients recorded their symptoms and results were sent to the provider. Patients received care guidelines for mild/moderate severity symptoms and a phone call from the provider for severe reports. RESULTS: A total of 282 patients generated > 119 088 data points. Patients completed 2860 of 3248 assigned surveys (88%), and 152 of 282 patients (54%) had symptom reports that generated an immediate notification to the provider. Longitudinal data were analyzed to determine whether previous reports predicted a notification alert and whether symptoms resolved after the alert was addressed. CONCLUSIONS: An electronic patient symptom management program was implemented in the midst of the COVID-19 pandemic. Enrollment of 282 patients and a high survey completion (88%) demonstrated feasibility/acceptance. Patients reported symptoms at severe levels of 54% of the time and received self-management instructions and provider phone calls that resolved or decreased the severity of the symptom. A standard approach and validated instrument provide opportunities for improving and benchmarking outcomes.},
	doi = {10.1016/j.jval.2022.01.023},
	pmid = {35339378 [Indexed for MEDLINE]},
	note = {PMC8941492}
}

@ARTICLE{10.12998/wjcc.v10.i6.1826,
	author = {Lu YY and Lu XM and Shao CY and Wang CC and Xu TT and Zhang BL},
	title = {Empathetic nursing with mindful cognitive therapy for fatigue, depression, and negative emotions in leukemia patients undergoing long-term chemotherapy.},
	journal = {World J Clin Cases},
	year = {2022},
	abstract = {BACKGROUND: Leukemia is a broad term for blood cell cancer. Leukemia is divided into acute or chronic, depending on cell differentiation. Leukemia patients are prone to adverse reactions during chemotherapy, such as anxiety, depression, and even suicide, affecting prognosis. As a nursing model developed by three well-known cognitive psychologists, empathetic nursing with mindfulness cognitive therapy (ENMCT) can effectively reduce anxiety and depression and improve the quality of life in patients with chronic disease. AIM: To explore the effect of ENMCT on cancer-induced fatigue, hope level, and negative emotions in patients with long-term leukemia chemotherapy. METHODS: A total of 103 patients with long-term leukemia chemotherapy diagnosed and treated in our hospital from July 2017 to October 2019 were enrolled and randomly assigned to observation and control groups using the random number table approach. Fifty-one patients in the control group received routine nursing, while 52 patients in the observation group received empathic nursing with mindfulness cognitive therapy. After three months of nursing care, cancer-induced fatigue was measured with the Piper Fatigue Scale (PFS), hope level with the Herth Hope Index (HHI), and negative emotion with the Hamilton Anxiety Scale (HAMA)/Hamilton Depression Scale (HAMD). Self-management (Chinese Strategies Used by People to Promote Health) was also recorded. RESULTS: The observation group's total scores in behavior, cognition, emotion, feeling, and PFS were lower than the control group after the intervention (P < 0.05). Keeping close contact with others, the attitude of taking positive actions, the attitude toward reality and future, and the total HHI score were higher in the observation group than the control group (P < 0.05). The observation group's HAMA and HAMD scores were lower than the control group (P < 0.05). The observation group's positive attitude, self-decision, and self-relief scores were greater than the control group (P < 0.05). CONCLUSION: Empathetic nursing with cognitive mindfulness therapy is beneficial in improving cancer-related fatigue, negative emotions, expectation level, and self-management ability in patients with long-term leukemia chemotherapy.},
	doi = {10.12998/wjcc.v10.i6.1826},
	pmid = {35317141},
	note = {PMC8891779}
}

@ARTICLE{10.1177/10781552211073576,
	author = {Elston Lafata J and Nguyen B and Staresinic C and Johnson M and Gratie D and Muluneh B},
	title = {Interpersonal communication-, education- and counselling-based interventions to support adherence to oral anticancer therapy: a systematic review.},
	journal = {J Oncol Pharm Pract},
	year = {2023},
	abstract = {Background. Many factors contribute to oral anti-cancer therapy adherence, including counselling and educational support. Objective. We systematically review the literature evaluating the effectiveness of interpersonal communication-, counselling- and education-based interventions on patient adherence to oral anticancer therapy. Methods. Using search terms pertaining to medication adherence, oral anticancer therapy, and communication, education, and counselling, we conducted a systematic search for full-text, original research articles prior to 3/13/20. Two reviewers independently reviewed each paper for inclusion and charted study information. Results. Twenty-four articles were included. All considered the use of oral anticancer therapy between two defined time points. Four studies also considered the length of time a patient persisted on therapy. Half (n = 12) of the studies reported a statistically significant relationship between the intervention and medication adherence, with no consistent pattern among intervention structure/content and effectiveness. Programmes offering in-person counselling and those targeting patients with chronic myeloid leukemia (CML), tended to report positive findings. Most studies faced substantial risk of bias, and only two reported using a behavioural theory to guide interventional content. Conclusions. Findings highlight the infancy of evidence base and need for rigorous and large-scale studies grounded in established behavioural theories to advance patient-targeted educational and counselling practices supporting adherence to oral anti-cancer therapy.},
	doi = {10.1177/10781552211073576},
	pmid = {35048768 [Indexed for MEDLINE]}
}

@ARTICLE{10.5737/23688076314470475,
	author = {Vinette B and Mrad H and El-Akhras A and Bilodeau K},
	title = {Synthesis of self-management strategies used by young adults who have undergone hematopoietic stem cell transplantation: A narrative review.},
	journal = {Can Oncol Nurs J},
	year = {2021},
	abstract = {Hematopoietic stem cell transplantation is frequently used to treat young adults with hematologic cancer. The treatment can cause a range of side effects that require patients to self-manage their symptoms. However, there do not seem to be any studies that review the literature on self-management strategies used by this group. The purpose of this paper is to summarize the self-management strategies used by young adults (18-39 years old) who have received a hematopoietic stem cell transplant for leukemia or lymphoma. A narrative review conducted in the CINAHL, MEDLINE and PsycINFO databases returned 11 papers. An analysis of these data shows that young adults use self-management strategies, including managing their emotions, turning to spiritual beliefs, seeking support from others and changing their behaviours. The results stress the importance of nursing care in supporting these self-management strategies used by young adults who have undergone hematopoietic stem cell transplantation.},
	doi = {10.5737/23688076314470475},
	pmid = {34786465},
	note = {PMC8565441}
}

@ARTICLE{10.3390/ijerph182111045,
	author = {Davis TC and Arnold CL and Mills G and Lesser GJ and Brown WM and Schulz R and Weaver KE and Pawloski PA},
	title = {Assessment of Oral Chemotherapy Nonadherence in Chronic Myeloid Leukemia Patients Using Brief Measures in Community Cancer Clinics: A Pilot Study.},
	journal = {Int J Environ Res Public Health},
	year = {2021},
	abstract = {The purpose of this pilot study was to assess Chronic Myeloid Leukemia (CML) patients' adherence to, beliefs about, and barriers to oral anticancer agents (OAC) using brief self-report measures in community-based cancer clinics. Patients completed a structured interview including a health literacy assessment, a Brief Medication Questionnaire, two single-item self-report adherence questions, and the Medications Adherence Reasons Scale. Of the 86 participants, 88.4% were white; 55.8% male; mean age, 58.7 years; and 22.1% had limited health literacy. Nonadherence (missing at least one dose in the last week) was reported by 18.6% of participants and associated (p < 0.003) with less-than-excellent perceived ability to take CML medications (16.3%). Black participants reported more difficulty taking CML medications than white participants (28.6% vs. 8.3%, p = 0.053). Among all participants, 43.0% reported their CML medicine was ineffective and 24.4% that taking CML pills was somewhat to very hard. The most common reasons for missing a dose were simply missed it (24.4%) and side effects (18.6%). Most patients perceived their ability to take CML medication was good to excellent, yet nearly one in five reported missing at least one dose in the last week. Brief, no-cost self-report assessments to screen CML patients' OAC adherence, barriers, and beliefs could facilitate counseling in busy community cancer clinics.},
	doi = {10.3390/ijerph182111045},
	pmid = {34769563 [Indexed for MEDLINE]},
	note = {PMC8582838}
}

@ARTICLE{10.3389/fonc.2021.701604,
	author = {Bucelli C and Fattizzo B and Cattaneo D and Giannotta JA and Barbullushi K and Pasquale R and Barozzi E and Barbanti MC and Pettine L and Rossi FG and Reda G and Cassin R and Barcellini W and Baldini L and Iurlo A},
	title = {Co-Occurrence of Myeloid and Lymphoid Neoplasms: Clinical Characterization and Impact on Outcome. A Single-Center Cohort Study.},
	abstract = {The co-occurrence of myeloid neoplasms and lymphoproliferative diseases (LPDs) has been epidemiologically described, particularly in myeloproliferative neoplasms (MPNs). However, the clinical features of these patients are poorly known. In this study, we evaluated a single-center cohort of 44 patients with a diagnosis of myeloid and LPD focusing on clinical features, therapy requirement, and outcome. The two diagnoses were concomitant in 32% of patients, while myeloid disease preceded LPD in 52% of cases (after a median of 37 months, 6-318), and LPD preceded myeloid neoplasm in 16% (after a median of 41 months, 5-242). The most prevalent LPD was non-Hodgkin lymphoma (50%), particularly lymphoplasmacytic lymphoma (54.5%), followed by chronic lymphocytic leukemia (27%), plasma cell dyscrasias (18.2%), and rarer associations such as Hodgkin lymphoma and Erdheim-Chester disease. Overall, 80% of BCR-ABL1-negative MPN patients required a myeloid-specific treatment and LPD received therapy in 45.5% of cases. Seven subjects experienced vascular events, 13 a grade >/= 3 infectious episode (9 pneumonias, 3 urinary tract infection, and 1 sepsis), and 9 developed a solid tumor. Finally, nine patients died due to solid tumor (four), leukemic progression (two), infectious complications (two), and brain bleeding (one). Longer survival was observed in younger patients (p = 0.001), with better performance status (p = 0.02) and in the presence of driver mutations (p = 0.003). Contrarily, a worse survival was significantly associated with the occurrence of infections (p < 0.0001). These data suggest that in subjects with co-occurrence of myeloid and lymphoid neoplasms, high medical surveillance for infectious complications is needed, along with patient education, since they may negatively impact outcome.},
	doi = {10.3389/fonc.2021.701604},
	pmid = {34733777},
	note = {PMC8558405}
}

@ARTICLE{10.1200/PO.21.00027,
	author = {Martin NA and Tepper JE and Giri VN and Stinchcombe TE and Cheng HH and Javle MM and Konnick EQ},
	title = {Adopting Consensus Terms for Testing in Precision Medicine.},
	journal = {JCO Precis Oncol},
	year = {2021},
	abstract = {Despite the well-understood benefits of biomarker and genetic testing in precision medicine, uptake remains low, particularly for patients with low socioeconomic status and minority ethnic backgrounds. Patients report having limited familiarity with testing terminology and may not be able to accurately explain testing's role in treatment decisions. Patient confusion and lack of understanding is exacerbated by a multiplicity of overlapping terms used in communicating about testing. A LUNGevity Foundation-led working group composed of five professional societies, 23 patient advocacy groups, and 19 industry members assessed and recommended specific terms for communicating with patients on testing for tumor characteristics and germline mutations. METHODS: Members completed a precision oncology testing framework analysis (biomarkers, germline variants, testing modalities, biospecimen, and commonly used testing terms) for nine solid tumors and blood cancers. The evaluation was segmented into terms that distinguish between somatic and germline testing. Additional data were captured in a comprehensive survey (1,650 respondents) led by FORCE (Facing Our Risk of Cancer Empowered) on patient preferences on germline testing terms. RESULTS: Thirty-three terms were noted in patient education related to biomarker, genetic, and genomic testing. Biomarker testing was selected as the preferred term for testing for somatic (acquired) alterations and other biomarkers. Genetic testing for an inherited mutation and genetic testing for inherited cancer risk were selected as the preferred terms for testing for germline variants. CONCLUSION: Democratizing comprehension about precision oncology testing through intentional use of plain language and common umbrella terminology by oncology health care providers and others in the oncology ecosystem may help improve understanding and communication, and facilitate shared decision making about the role of appropriate testing in treatment decisions and other aspects of oncology care.},
	doi = {10.1200/PO.21.00027},
	pmid = {34651094 [Indexed for MEDLINE]},
	note = {PMC8509918}
}

@ARTICLE{10.1177/23743735211034967,
	author = {Kranzler EC and Olson JS and Nichols HM and Yuen EY and McManus S and Buzaglo JS and Zaleta AK},
	title = {Patient-Reported Communication With Their Health Care Team About New Treatment Options for Chronic Lymphocytic Leukemia.},
	journal = {J Patient Exp},
	year = {2021},
	abstract = {Chronic lymphocytic leukemia (CLL) often requires consideration of multiple treatment options. Shared decision-making (SDM) is important, given the availability of increasingly novel therapies; however, patient-provider treatment conversations vary. We examined relationships between patient-provider discussions of new CLL treatment options and sociodemographic, clinical, and patient-provider communication variables among 187 CLL patients enrolled in Cancer Support Community's Cancer Experience Registry. Factors significantly associated with self-reports of whether patients' providers discussed new CLL treatment options with them were examined using χ2 tests, t tests, and hierarchical logistic regression. Fifty-eight percent of patients reported discussing new treatment options with their doctor. Patients with higher education were 3 times more likely to discuss new treatment options relative to those with lower education (OR = 3.06, P < .05). Patients who experienced a cancer recurrence were 7 times more likely to discuss new treatment options compared to those who had not (OR = 7.01, P < .05). Findings offer insights into the correlates of patient-provider discussions of new CLL treatment options. As novel therapies are incorporated into standards of care, opportunities exist for providers to improve patient care through enhanced SDM.},
	doi = {10.1177/23743735211034967},
	pmid = {34458567},
	note = {PMC8392805}
}

@ARTICLE{10.1016/j.jgo.2021.07.010,
	author = {Rosko A and Huang Y and Jones D and Presley CJ and Jaggers J and Owens R and Naughton M and Krok-Schoen JL},
	title = {Feasibility of implementing an exercise intervention in older adults with hematologic malignancy.},
	journal = {J Geriatr Oncol},
	year = {2022},
	abstract = {Older adults with Hematologic Malignancy (HM) are vulnerable to functional decline secondary to disease and treatment. Interventions for physical deconditioning, in concert with routine hematology care are limited. The feasibility of accrual, retention, and demand for an exercise intervention among a high-risk HM population was piloted. METHODS: Older adults with HM, on active treatment, with functional impairment were recruited prospectively to participate in a 6-month Otago Exercise Programme (OEP). Measures of motivation, self-efficacy, patient identified barriers to exercise, barriers to clinical trial enrollment, study satisfaction, and serious adverse events were captured. RESULTS: 63 patients were approached, 18 declined trial enrollment, 45 consented, 30 patients enrolled in the exercise program. The main barrier for trial enrollment was transportation/travel concerns (n = 15). Of the 45 consented participants, 8 (12.7%) dropped out due to clinical deterioration, 5 (7.9%) withdrew, and 2 (3.2%) were ineligible prior to exercise-intervention intiation. The median age was 75.5 years (range 62-83) with plasma cell dyscrasia (63%), non-Hodgkin lymphoma (20%) and leukemia (17%). Retention of the physical therapist (PT) led-OEP was 76.6% of patients (n = 23/30), and end-of-study retention was 66.7% (n = 20/30). Of the evaluable patients, 23/29 completed the PE-led OEP yielding a completion rate of 79%. Participants were extremely motivated (72.4%) and strongly intended (89.7%) to engage in regular physical activity. Exercising when tired increased from a median score of 50 at Visit 1 to 70 at Visit 2, but dropped significantly to 45 at Visit 3 (p < 0.001). Participants reported significantly lower self-efficacy to exercise over the next 6 months from Visit 1 to Visit 3 (p = 0.001). CONCLUSIONS: Older patients with HM had higher completion of in-person, PT-led exercise compared to at-home, independent exercise. Older adults were motivated and found the program acceptable, yet the ability to sustain a structured exercise program was challenging due to changes in health status. ClinicalTrials.gov Identifier: NCT02791737.},
	doi = {10.1016/j.jgo.2021.07.010},
	pmid = {34446377 [Indexed for MEDLINE]},
	note = {PMC8863976}
}

@ARTICLE{34267029 [Indexed for MEDLINE],
	author = {Sekiguchi Y and Iizuka H and Takizawa H and Mitsumori T and Tomita S and Izumi H and Okubo M and Miyake K and Osawa T and Sawada T and Yoshikawa S and Noguchi M},
	title = {Use of Ibrutinib in 10 Patients with Treatment-Naïve or Relapsed/Refractory Chronic Lymphocytic Leukemia/Small Lymphocytic Lymphoma in Real-World Clinical Practice -A Report from a Single Medical Institution.},
	journal = {Gan To Kagaku Ryoho},
	year = {2021},
	abstract = {In Japan, ibrutinib has been approved as both a front-line and later-line treatment for chronic leukemia/small lymphocytic lymphoma(CLL/SLL). However, little is known about the actual outcomes and adverse events(AEs)associated with the use of ibrutinib in Japanese patients. OBJECTIVE: The outcomes and AEs of patients treated with ibrutinib in a real-world setting were investigated. METHODS: A retrospective cohort study of all patients with CLL/SLL who were treated with ibrutinib at a single institution was conducted. RESULT: In total, 10 patients, including 5 treatment-naïve patients(50%), were enrolled. The median follow-up period was 9.8 months(range, 0.2-21.6 months), and the estimated overall response rate (ORR: complete remission plus partial remission)was 60%. The median overall survival and progression-free survival outcomes were not reached. During the follow-up period, 4 patients(40%)had at least one AE and 1 patient(10%)had at least one grade≥3 AE. Ibrutinib was discontinued in 4 patients(40%)because of AEs in 2 patients(20%), the progression of CLL in 1 patient(10%), and financial reasons in 1 patient(10%). Richter's transformation did not occur in any of the cases. CONCLUSION: The ORR was lower(60%)than that observed in clinical trials. The frequency and severity of AEs were both relatively low, although the discontinuation rate was high(40%). Patient education and medication adherence were considered important.},
	pmid = {34267029 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.pec.2021.06.025,
	author = {Ector GI and Verweij L and Hermens RP and Blijlevens NM},
	title = {Filling the gaps of patient information needs and information perception in chronic myeloid leukemia with the patient-physician co-produced web-based platform CMyLife.},
	journal = {Patient Educ Couns},
	year = {2022},
	abstract = {BACKGROUND: For patients with chronic myeloid leukemia, a web-based platform CMyLife was developed. Its aim is to enhance patient empowerment, by adequate information provision, among others. Before evaluating its effect, information provision and needs in current care were assessed. OBJECTIVE: To assess patients' evaluation of received information and information needs before CMyLife utilization and whether this information source is used correspondingly. Additionally, we explored predicting patient factors in information perception. PATIENT INVOLVEMENT: CMyLife platform was developed with active patient participation. METHODS: We conducted a cross-sectional survey among 203 CML patients before launch of the CMyLife platform, using validated questionnaires on information provision and predictive factors. We focused on website utilization during the first 3 years, using Google Analytics. Regression analyses were performed to determine influence of patient factors on information perception. RESULTS: Global perceived information provision was scored 42.8 (0-100). Information on other services such as rehabilitation and psychological support, and effects of treatment on sexuality showed room for improvement. One out of 3 knew where to find useful health information online. But more information was desired by 36% of them. Age ≥65 years, time since diagnosis and low education were positively associated with this need. Pages on medication and side effects were visited the most. DISCUSSION: To fill the gap in perceived provision and needs, information should be adjusted more to the individual in content, manner and timing. Age, time since diagnosis, and educational level are of influence in perceived information, and specific needs within these groups should be further explored. PRACTICAL VALUE: CMyLife provides reliable and up-to-date information for low eHealth literacy skilled patients concerning multiple topics indicated by patients.},
	doi = {10.1016/j.pec.2021.06.025},
	pmid = {34226069 [Indexed for MEDLINE]}
}

@ARTICLE{10.1093/abm/kaab035,
	author = {Hyland KA and Nelson AM and Eisel SL and Hoogland AI and Ibarz-Pinilla J and Sweet K and Jacobsen PB and Knoop H and Jim HSL},
	title = {Fatigue Perpetuating Factors as Mediators of Change in a Cognitive Behavioral Intervention for Targeted Therapy-Related Fatigue in Chronic Myeloid Leukemia: A Pilot Study.},
	journal = {Ann Behav Med},
	year = {2022},
	abstract = {BACKGROUND: Cognitive behavioral therapy for targeted-therapy related fatigue (CBT-TTF) has demonstrated preliminary efficacy in reducing fatigue in patients treated with tyrosine kinase inhibitors (TKIs) for chronic myeloid leukemia (CML). PURPOSE: The aim of the current analyses was to explore whether fatigue perpetuating factors (disturbed sleep/wake cycle, dysregulated activity patterns, maladaptive cognitions about fatigue and cancer, insufficient processing of cancer and treatment, inadequate social support and interactions, heightened fear of cancer progression) changed over time in patients receiving CBT-TTF, and whether the effect of CBT-TTF on fatigue was mediated by these factors. METHODS: Secondary data analyses were conducted from a pilot randomized controlled trial. Patients with CML treated with a TKI who reported moderate to severe fatigue were randomized 2:1 to CBT-TTF delivered via FaceTime for iPad or a waitlist control condition (WLC). Self-report measures of fatigue and fatigue perpetuating factors were obtained before randomization and post-intervention (i.e., approximately 18 weeks later). Mixed model and mediation analyses using bootstrap methods were used. RESULTS: A total of 36 participants (CBT-TTF n = 22, WLC n = 14) who had baseline and 18-week follow-up data and attended >5 sessions for CBT-TTF were included. Participants randomized to CBT-TTF reported improvements in activity (mental, physical, social, p's ≤ .023) and cognitions (helplessness, catastrophizing, focusing on symptoms, self-efficacy, p's ≤ .003) compared to WLC. Mental activity, social activity, self-efficacy, helplessness, and focusing on symptoms, as well as sleep and insufficient processing (avoidance) mediated the relationship between treatment group and fatigue. CONCLUSIONS: CBT-TTF appears to improve TKI-related fatigue in CML patients through changes in behavior (sleep, activity patterns) and cognitions about fatigue and cancer. A larger randomized controlled trial is warranted to confirm these findings.},
	doi = {10.1093/abm/kaab035},
	pmid = {33991085 [Indexed for MEDLINE]},
	note = {PMC8832107}
}

@ARTICLE{10.1016/j.ejon.2021.101951,
	author = {Vinette B and Bilodeau K},
	title = {Progression of self-management learning experiences of young adults following an allogeneic hematopoietic stem cell transplantation: A qualitative study.},
	journal = {Eur J Oncol Nurs},
	year = {2021},
	abstract = {PURPOSE: Hematological diseases are among the most common forms of cancer that can affect young adults. Hematopoietic stem cell transplantation is a common intervention to treat blood-related cancers such as leukemia and lymphoma. Allogeneic stem cell transplants can provoke many acute and chronic symptoms. Young adult cancer survivors are expected to develop expertise to self-manage these symptoms. However, learning self-management can be quite challenging for young adults. This paper aims to describe the symptoms self-management learning experiences of young adults following an allogeneic stem cell transplant. METHOD: A qualitative descriptive study was conducted to describe self-management learning experiences of young adults (18-39 years old) following an allogeneic stem cell transplant. Semi-structured interviews were conducted (n = 7, mean age 26 years old, mean time since allogeneic stem cell transplant was 14,71 months). Iterative qualitative content analysis was performed. RESULTS: Participants who had undergone an allogeneic stem cell transplant described learning self-management as a progressive process, with expertise having to be developed through experience. Certain factors could positively or negatively affect the learning process and hence the development of this self-management expertise. With time, these young adults developed interoceptive ability and body awareness related to their symptoms, which influenced their self-management. CONCLUSIONS: Following an allogeneic stem cell transplant, young adults need to be supported during their survivorship to develop self-management expertise. Nurses must adapt care according to patients' level of expertise to promote autonomy, development of interoceptive ability, and acquisition of self-management skills.},
	doi = {10.1016/j.ejon.2021.101951},
	pmid = {33774375 [Indexed for MEDLINE]}
}

@ARTICLE{10.1080/10428194.2021.1901096,
	author = {Pemmaraju N and Wilson NR and Clementi Doan T and Qiao W and Peterson SK and Zoeller V and Schorr A and Verstovsek S},
	title = {Myeloproliferative neoplasm questionnaire: assessing patient disease knowledge in the modern digital information era.},
	journal = {Leuk Lymphoma},
	year = {2021},
	abstract = {There is growing Internet and social media use among patients with rare blood cancers, notably myeloproliferative neoplasms (MPNs). A 38-item online questionnaire was developed to assess patients' (n = 983) disease understanding and use of online resources regarding MPN. Many responders (74%) reported unawareness of additional mutations beyond their primary molecular marker(s); 32% were unsure of their prognostic risk stratification. Additionally, 89% reported using online resources (Facebook (61%); Google/Google+ (42%); YouTube (34%); blogs (26%); Twitter (5%)) to seek information about MPN. Despite this, results showed many gaps in patients' basic disease knowledge. Our findings suggest an important difference in social media habits between physicians and patients: physicians are rapidly adopting Twitter as their preferred medium for sharing medical knowledge; however, patients often prefer other social mediums. Educational campaigns should be designed in more personalized ways, aiming to fit a variety of online platforms to maximize reach and impact for patients with MPN.},
	doi = {10.1080/10428194.2021.1901096},
	pmid = {33749512 [Indexed for MEDLINE]},
	note = {PMC9938727}
}

@ARTICLE{10.6004/jadpro.2021.12.1.5,
	author = {Goodrich A},
	title = {Advanced Practice Perspectives on Preventing and Managing Tumor Lysis Syndrome and Neutropenia in Chronic Lymphocytic Leukemia.},
	journal = {J Adv Pract Oncol},
	year = {2021},
	abstract = {Tumor lysis syndrome (TLS) and neutropenia are significant toxicities in the treatment of chronic lymphocytic leukemia (CLL). Both TLS and neutropenia can lead to potentially life-threatening complications for patients with chronic lymphocytic leukemia undergoing antineoplastic therapy. This article focuses on diligent risk assessment, prophylaxis, early identification, monitoring, patient education, and prompt intervention for TLS and neutropenia. These are all necessary steps to reduce life-threatening complications. Guidelines are available for risk assessments for both TLS and neutropenia. Once risk is established, prophylaxis and monitoring recommendations can be found in available guidelines. There are no established guidelines or widely used decision-making standards for the treatment of clinical TLS. General management strategies are well documented in the literature, with some degree of customization to each individual patient. If fever occurs in the setting of neutropenia, there are well-established guidelines for management, including guidance on anti-infective agents and use of growth factors. In addition, awareness and proper actions regarding TLS and neutropenia are key to preventing treatment delays, dose reductions, or treatment discontinuation. Adequate planning for TLS and neutropenia is critical to optimize patient outcomes.},
	doi = {10.6004/jadpro.2021.12.1.5},
	pmid = {33552662},
	note = {PMC7844191}
}

@ARTICLE{10.1097/CIN.0000000000000690,
	author = {Song CE and An M},
	title = {The Self-management Smartphone Application for Cancer Survivors, ReLive: Development and Usability Testing.},
	journal = {Comput Inform Nurs},
	year = {2021},
	abstract = {ReLive is a nursing theory-driven and evidence-based smartphone application that aims to promote self-management among cancer survivors. It has been designed to display symptom measurement results in different traffic light colors, depending on the severity of a user's symptoms (eg, severe symptoms are presented in red). Therefore, it is easy for users to draw inferences about changes in their symptoms. Further, users can simultaneously set several physical activity goals and monitor their performance. Social support, self-efficacy, and quality of life of a user can also be monitored regularly. This study investigated the usability of this application. An iterative formative test, including a cognitive walkthrough and face-to-face interviews, was conducted. Participants were seven individuals with a diagnosis of chronic myeloid leukemia. The ease of use and understanding, acceptability, and usefulness of the application were evaluated. The results revealed that the participants had evaluated ReLive positively. This program could be used as an intervention to deliver health information and manage their performance. Further research is needed to assess the application's effects on self-management among survivors of various types of cancers.},
	doi = {10.1097/CIN.0000000000000690},
	pmid = {33214389 [Indexed for MEDLINE]}
}

@ARTICLE{10.1007/s00520-020-05819-w,
	author = {Nørskov KH and Overgaard D and Boesen J and Struer A and El-Azem SEWD and Tolver A and Lomborg K and Kjeldsen L and Jarden M},
	title = {Patient ambassador support in newly diagnosed patients with acute leukemia during treatment: a feasibility study.},
	journal = {Support Care Cancer},
	year = {2021},
	abstract = {PURPOSE: This study investigated the feasibility of patient ambassador support in newly diagnosed patients with acute leukemia during treatment. METHODS: A multicenter single-arm feasibility study that included patients newly diagnosed with acute leukemia (n = 36) and patient ambassadors previously treated for acute leukemia (n = 25). Prior to the intervention, all patient ambassadors attended a 6-h group training program. In the intervention, patient ambassadors provided 12 weeks of support for patients within 2 weeks of being diagnosed. Outcome measures included feasibility (primary outcome), safety, anxiety, and depression measured by the Hospital Anxiety and Depression Scale, quality of life by the Functional Assessment of Cancer Therapy-Leukemia and the European Organization for Research and Treatment of Cancer Quality of Life Questionnaire, and symptom burden by MD Anderson Symptom Inventory, the Patient Activation Measure, and the General Self-Efficacy Scale. RESULTS: Patient ambassador support was feasible and safe in this population. Patients and patient ambassadors reported high satisfaction with the individually adjusted support, and patients improved in psychosocial outcomes over time. Patient ambassadors maintained their psychosocial baseline level, with no adverse events, and used the available support to exchange experiences with other patient ambassadors and to manage challenges. CONCLUSION: The patient ambassador support program is feasible and has the potential to be a new model of care incorporated in the hematology clinical care setting, creating an active partnership between patients and former patients. This may strengthen the existing supportive care services for patients with acute leukemia. TRIAL REGISTRATION: NCT03493906.},
	doi = {10.1007/s00520-020-05819-w},
	pmid = {33051828 [Indexed for MEDLINE]},
	note = {PMC8062400}
}

@ARTICLE{10.1177/1078155220964539,
	author = {Tan BK and Chua SS and Chen LC and Chang KM and Balashanker S and Bee PC},
	title = {Acceptability of pharmacist-led interventions to resolve drug-related problems in patients with chronic myeloid leukaemia.},
	journal = {J Oncol Pharm Pract},
	year = {2021},
	abstract = {PURPOSE: Chronic myeloid leukaemia (CML) patients on long-term tyrosine kinase inhibitor (TKI) therapy are susceptible to drug-related problems (DRPs). This study aimed to evaluate the acceptability and outcomes of pharmacist-led interventions on DRPs encountered by CML patients. METHODS: This study included participants from the intervention arm of a randomised controlled trial which was conducted to evaluate the effects of pharmacist-led interventions on CML patients treated with TKIs. Participants were recruited and followed up in the haematology clinics of two hospitals in Malaysia from March 2017 to January 2019. A pharmacist identified DRPs and helped to resolve them. Patients were followed-up for six months, and their DRPs were assessed based on the Pharmaceutical Care Network Europe Classification for DRP v7.0. The identified DRPs, the pharmacist's interventions, and the acceptance and outcomes of the interventions were recorded. A Poisson multivariable regression model was used to analyse factors associated with the number of identified DRPs per participant. RESULTS: A total of 198 DRPs were identified from 65 CML patients. The median number of DRPs per participants was 3 (interquartile range: 2, 4). Most participants (97%) had at least one DRP, which included adverse drug events (45.5%), treatment ineffectiveness (31.5%) and patients' treatment concerns or dissatisfaction (23%). The 228 causes of DRPs identified comprised the following: lack of disease or treatment information, or outcome monitoring (47.8%), inappropriate drug use processes (23.2%), inappropriate patient behaviour (19.9%), suboptimal drug selection (6.1%), suboptimal dose selection (2.6%) and logistic issues in dispensing (0.4%). The number of concomitant medications was significantly associated with the number of DRPs (adjusted Odds Ratio: 1.100; 95% CI: 1.005, 1.205; p = 0.040). Overall, 233 interventions were made. These included providing patient education on disease states or TKI-related side effects (75.1%) and recommending appropriate instructions for taking medications (7.7%). Of the 233 interventions, 94.4% were accepted and 83.7% were implemented by the prescriber or patient. A total of 154 DRPs (77.3%) were resolved. CONCLUSIONS: The pharmacist-led interventions among CML patients managed to identify various DRPs, were well accepted by both TKI prescribers and patients, and had a high success rate of resolving the DRPs.},
	doi = {10.1177/1078155220964539},
	pmid = {33040675 [Indexed for MEDLINE]}
}

@ARTICLE{10.1007/s00277-020-04045-y,
	author = {Zerbit J and Chevret S and Bernard S and Kroemer M and Ablard C and Harel S and Brice P and Madelaine I and Thieblemont C},
	title = {Improved time to treatment failure and survival in ibrutinib-treated malignancies with a pharmaceutical care program: an observational cohort study.},
	journal = {Ann Hematol},
	year = {2020},
	abstract = {Ibrutinib treatment has been shown to increase survival in patients with B cell malignancies. Real-life data suggest a large part of discontinuations are due to toxicities, impairing ibrutinib efficacy. We aimed to assess the impact of a pharmaceutical care program on the efficacy and safety of ibrutinib. This single-center, cohort, observational study enrolled patients with B cell malignancies. Patients were either assigned to the program or to receive usual care, based on physician decision. The program was conducted by clinical pharmacists specializing in oncology and included patient education for management of toxicities, adherence monitoring, interventions to reduce drug-drug interactions, and follow-up of transition from hospital to community. Between February 2014 and May 2017, we enrolled 155 patients, including 42 (27%) who were allocated to the program group and 113 (73%) to the usual care group. The effect of the program was beneficial in terms of time to treatment failure (p = 0.0005). The 30-month progression-free and overall survivals were significantly superior in the program group (respectively p = 0.002 and p = 0.004). Grade 3 or higher adverse events occurred more frequently for patients in the usual care group (15%) than program group (8%). A pharmaceutical care program provides a personalized environment for outpatient monitoring and control of the key risks associated with oral anticancer agents. This study shows evidence that management of ibrutinib treatment by clinical pharmacists results in significant improvement in survival and better tolerance than usual care.},
	doi = {10.1007/s00277-020-04045-y},
	pmid = {32483668 [Indexed for MEDLINE]},
	note = {PMC7316844}
}

@ARTICLE{10.2196/15895,
	author = {Ector GI and Westerweel PE and Hermens RP and Braspenning KA and Heeren BC and Vinck OM, de Jong JJ and Janssen JJ and Blijlevens NM},
	title = {The Development of a Web-Based, Patient-Centered Intervention for Patients With Chronic Myeloid Leukemia (CMyLife): Design Thinking Development Approach.},
	journal = {J Med Internet Res},
	year = {2020},
	abstract = {BACKGROUND: With the global rise in chronic health conditions, health care is transforming, and patient empowerment is being emphasized to improve treatment outcomes and reduce health care costs. Patient-centered innovations are needed. We focused on patients with chronic myeloid leukemia (CML), a chronic disease with a generally good long-term prognosis because of the advent of tyrosine kinase inhibitors. However, both medication adherence by patients and guideline adherence by physicians are suboptimal, unnecessarily jeopardizing treatment outcomes. OBJECTIVE: The aim of this study was to develop a patient-centered innovation for patients with CML using a design thinking methodology. METHODS: The 5 phases of design thinking (ie, empathize, define, ideate, prototype, and test) were completed, and each phase started with the patient. Stakeholders and end users were identified and interviewed, and observations in the care system were made. Using tools in human-centered design, problems were defined and various prototypes of solutions were generated. These were evaluated by patients and stakeholders and then further refined. RESULTS: The patients desired (1) insights into their own disease; (2) insights into the symptoms experienced, both in terms of knowledge and comprehension; and (3) improvements in the organization of care delivery. A web-based platform, CMyLife, was developed and pilot-tested. It has multiple features, all targeting parts of the bigger solution, including a website with reliable information and a forum, a guideline app, personal medical records with logs of symptoms and laboratory results (including a molecular marker and linked to the guideline app), tailored feedback based on the patients' symptoms and/or results, screen-to-screen consulting, delivery of medication, and the collection of blood samples at home. CONCLUSIONS: The multifeatured innovation, CMyLife, was developed in a multidisciplinary way and with active patient participation. The aim of developing CMyLife was to give patients the tools to monitor their results, interpret these results, and act on them. With this tool, they are provided with the know-how to consider their results in relation to their personal care process. Whether CMyLife achieves its goal and the evaluation of the added value will be the focus of future studies. CML could become the first malignancy for which patients are able to monitor and manage their disease by themselves.},
	doi = {10.2196/15895},
	pmid = {32412424 [Indexed for MEDLINE]},
	note = {PMC7260663}
}

@ARTICLE{10.2196/17018,
	author = {Arts LPJ and Oerlemans S and Posthuma EFM and Issa DE and Oosterveld M, van der Griend R and Nijziel MR, van de Poll-Franse LV},
	title = {Web-Based Self-Management for Patients With Lymphoma: Assessment of the Reach of Intervention of a Randomized Controlled Trial.},
	journal = {J Med Internet Res},
	year = {2020},
	abstract = {BACKGROUND: Randomized controlled trials (RCTs) often provide accurate estimates of the internal validity of an intervention but lack information on external validity (generalizability). We conducted an RCT on the effectiveness of a self-management intervention among patients with lymphoma in a population-based setting. OBJECTIVE: The objectives of the current study were to describe the proportion of RCT participants compared to all patients invited to participate, and compare sociodemographic and clinical characteristics of RCT participants with all respondents, all patients invited to participate, and all patients selected from the Netherlands Cancer Registry (NCR) to determine the reach of the intervention. An additional objective was to assess differences on RCT outcome variables between RCT and paper respondents. METHODS: Patients with lymphoma or chronic lymphocytic leukemia ≥18 years old at diagnosis from 13 hospitals in the Netherlands were selected from the population-based NCR, which routinely collects data on sociodemographic and clinical characteristics. Eligible patients were invited to participate in an RCT and complete a questionnaire. Web-based completion determined RCT enrollment, whereas paper respondents were followed observationally. RESULTS: A total of 1193 patients were selected from the NCR, 892 (74.77%) of whom were invited to participate in the trial by their hematologist after verifying eligibility. Among those invited, 25.4% (227/892) completed the web-based questionnaire and were enrolled in the RCT. The RCT participants were younger and there was a higher proportion of men than nonparticipants (P<.001). In addition, 25.7% (229/892) of those invited opted to participate in the paper-based observational follow-up study. Compared with paper respondents, RCT participants were younger (P<.001), with a higher proportion of men (P=.002), and had higher education levels (P=.02). RCT participants more often wanted to receive all available information on their disease (P<.001), whereas paper respondents reported higher levels of emotional distress (P=.009). CONCLUSIONS: From a population-based sample of eligible patients, the participation rate in the RCT was approximately 25%. RCT participants may not be representative of the target population because of different sociodemographic and clinical characteristics. Since RCT participants represent a minority of the target population, RCT results should be interpreted with caution as patients in the RCT may be those least in need of a self-management intervention. TRIAL REGISTRATION: Netherlands Trial Register NTR5953; https://www.trialregister.nl/trial/5790.},
	doi = {10.2196/17018},
	pmid = {32406858 [Indexed for MEDLINE]},
	note = {PMC7256744}
}

@ARTICLE{10.1182/blood.2019003116,
	author = {Geyer HL and Gazelka H and Mesa R},
	title = {How I treat pain in hematologic malignancies safely with opioid therapy.},
	journal = {Blood},
	year = {2020},
	abstract = {The field of malignant hematology has experienced extraordinary advancements with survival rates doubling for many disorders. As a result, many life-threatening conditions have since evolved into chronic medical ailments. Paralleling these advancements have been increasing rates of complex hematologic pain syndromes, present in up to 60% of patients with malignancy who are receiving active treatment and up to 33% of patients during survivorship. Opioids remain the practice cornerstone to managing malignancy-associated pain. Prevention and management of opioid-related complications have received significant national attention over the past decade, and emerging data suggest that patients with cancer are at equal if not higher risk of opioid-related complications when compared with patients without malignancy. Numerous tools and procedural practice guides are available to help facilitate safe prescribing. The recent development of cancer-specific resources directing algorithmic use of validated pain screening tools, prescription drug monitoring programs, urine drug screens, opioid use disorder risk screening instruments, and controlled substance agreements have further strengthened the framework for safe prescribing. This article, which integrates federal and organizational guidelines with known risk factors for cancer patients, offers a case-based discussion for reviewing safe opioid prescribing practices in the hematology setting.},
	doi = {10.1182/blood.2019003116},
	pmid = {32352512 [Indexed for MEDLINE]},
	note = {PMC8765122}
}

@ARTICLE{10.2217/fon-2019-0555,
	author = {Gambacorti-Passerini C, le Coutre P and Piazza R},
	title = {The role of bosutinib in the treatment of chronic myeloid leukemia.},
	journal = {Future Oncol},
	year = {2020},
	abstract = {The availability of several BCR-ABL1 tyrosine kinase inhibitor (TKI) options means physicians and patients can select the most appropriate treatment for a patient with chronic myeloid leukemia (CML). BCR-ABL TKI selection as a first- or later-line therapy is dependent on a number of clinical factors. Regular monitoring of patients, patient education, dose optimization and management of treatment-emergent adverse events are key aspects of long-term chronic myeloid leukemia management and contribute to improved clinical outcomes, quality of life, patient adherence and healthcare costs. This review provides an overview of the BCR-ABL1 TKI bosutinib, its pharmacology and clinical trials; discusses the impact of comorbidities and concomitant medications on bosutinib treatment selection; and suggests strategies for managing adverse events and dose optimization during bosutinib treatment.},
	doi = {10.2217/fon-2019-0555},
	pmid = {31833784 [Indexed for MEDLINE]}
}

@ARTICLE{10.1089/jayao.2019.0063,
	author = {Saita E and Acquati C},
	title = {Evaluating the Framed Portrait Experience as an Intervention to Enhance Self-Efficacy and Self-Esteem in a Sample of Adolescent and Young Adult Cancer Survivors: Results of a Pilot Study.},
	journal = {J Adolesc Young Adult Oncol},
	year = {2020},
	abstract = {Cancer diagnosis and treatments negatively affect quality of life and developmental processes of adolescents and young adults (AYAs), with self-esteem, self-efficacy, and body image discomfort reported. Despite increasing awareness of the psychosocial issues experienced by this group, a paucity of psychosocial interventions has been developed. This study aims to investigate the Framed Portrait Experience (FPE) as an intervention to promote well-being among AYA cancer survivors. A pilot study was conducted using a quasi-experimental design. The sample included 18 AYA leukemia survivors. Individuals in the intervention group (n = 10) participated in the FPE, a psychosocial program consisting of two sessions. In the first one, starting from the illness narrative recollected by the individual, pictures representing the subject in meaningful contexts are taken. Then, a selected number of pictures are used in a second encounter with a therapist to integrate the disease within past, present, and future of the participant. Survivors in the comparison group (n = 8) were offered usual psychosocial care at the participating institute. Measures of personality traits, coping, self-efficacy, self-esteem, and body image were compared at pre-test and 3 months later. Significant differences in self-efficacy and self-esteem scores were identified at post-test between the intervention and comparison group (p < 0.05). No significant differences were identified for body self-esteem. These findings provide initial evidence supporting the FPE as a low-cost and easy-to-implement intervention to promote self-efficacy and self-esteem among AYA survivors. Further research with larger samples, with more rigorous designs, and different cancer types is needed.},
	doi = {10.1089/jayao.2019.0063},
	pmid = {31742467 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.ejon.2019.07.006,
	author = {White LL and Kupzyk KA and Berger AM and Cohen MZ and Bierman PJ},
	title = {Self-efficacy for symptom management in the acute phase of hematopoietic stem cell transplant: A pilot study.},
	journal = {Eur J Oncol Nurs},
	year = {2019},
	abstract = {PURPOSE: Hematopoietic stem cell transplant (HSCT) is an intensive treatment associated with distressing treatment and disease-related symptoms that affect patient outcomes such as functional status and quality of life. Self-efficacy for symptom management (SESM) is a person's belief in their ability to perform behaviors to prevent and relieve symptoms. Presence of SESM can impact symptom distress and functional status. This study describes the changes over time and relationships among SESM, symptom distress, and physical functional status in adults during the acute phase of HSCT. METHODS: Patients (n = 40) completed measures of symptom distress, SESM, and physical function at time points prior to and at days 7, 15 and 30 post-transplant. Clinical outcomes were length of stay and number of readmissions. RESULTS: Symptom distress, physical function, and SESM changed significantly over time. There was a significant negative relationship between symptom distress and physical function and between symptom distress and SESM at all points. The lowest levels of SESM and physical function were at day 7 when symptom distress was highest. Symptom distress was a moderator for the relationship between physical function and SESM at day 15. CONCLUSION: This was the first study to examine SESM in the acute phase of HSCT. Higher SESM was associated with fewer symptoms and increased physical function. Less symptom distress was associated with higher physical function and confidence to manage symptoms. These findings provide the basis for development of patient-centered interventions to enhance SESM when symptoms are at their highest immediately after HSCT.},
	doi = {10.1016/j.ejon.2019.07.006},
	pmid = {31446260 [Indexed for MEDLINE]}
}

@ARTICLE{10.1093/jncimonographs/lgz012,
	author = {Carrozzo M and Eriksen JG and Bensadoun RJ and Boers-Doets CB and Lalla RV and Peterson DE},
	title = {Oral Mucosal Injury Caused by Targeted Cancer Therapies.},
	journal = {J Natl Cancer Inst Monogr},
	year = {2019},
	abstract = {Targeted cancer therapies have fundamentally transformed the treatment of many types of cancers over the past decade, including breast, colorectal, lung, and pancreatic cancers, as well as lymphoma, leukemia, and multiple myeloma. The unique mechanisms of action of these agents have resulted in many patients experiencing enhanced tumor response together with a reduced adverse event profile as well. Toxicities do continue to occur, however, and in selected cases can be clinically challenging to manage. Of particular importance in the context of this monograph is that the pathobiology for oral mucosal lesions caused by targeted cancer therapies has only been preliminarily investigated. There is distinct need for novel basic, translational, and clinical research strategies to enhance design of preventive and therapeutic approaches for patients at risk for development of these lesions. The research modeling can be conceptually enhanced by extrapolating "lessons learned" from selected oral mucosal conditions in patients without cancer as well. This approach may permit determination of the extent to which pathobiology and clinical management are either similar to or uniquely distinct from oral mucosal lesions caused by targeted cancer therapies. Modeling associated with oral mucosal disease in non-oncology patients is thus presented in this context as well. This article addresses this emerging paradigm, with emphasis on current mechanistic modeling and clinical treatment. This approach is in turn designed to foster delineation of new research strategies, with the goal of enhancing cancer patient treatment in the future.},
	doi = {10.1093/jncimonographs/lgz012},
	pmid = {31425602 [Indexed for MEDLINE]}
}

@ARTICLE{10.1177/1078155219864640,
	author = {Reff MJ and Shillingburg A and Shah B and Elder C and Prescott H and Kennerly-Shah J},
	title = {Front-line use of tyrosine kinase inhibitors in chronic phase chronic myeloid leukemia: Practice considerations.},
	journal = {J Oncol Pharm Pract},
	year = {2020},
	abstract = {The development of BCR-ABL-targeting tyrosine kinase inhibitors has transformed chronic phase chronic myeloid leukemia (CP CML) from a disease with a terminal prognosis to a treatable chronic illness. Long-term treatment with tyrosine kinase inhibitors means that patients have to be clinically managed and monitored over extended periods of time, thus a patient-centered, medically integrated, and multidisciplinary oncology healthcare team is required to support patients through their journey. Pharmacists work with patients, physicians, and the wider support team to select the optimum therapy plan for a given patient. These decisions are based on risk factors, comorbidities, concomitant medications, and personal circumstances and pharmacists advise on the efficacy and safety of different treatment options. Additionally, pharmacists are a key point-of-contact and resource for monitoring patient response to treatment, identifying and managing adverse events and drug-drug interactions, any subsequent therapy plan modifications, and, potentially, treatment-free remission. Pharmacists also assist with patient education, medication adherence, and financial discussions with patients throughout the long course of the disease. This review provides an overview of BCR-ABL tyrosine kinase inhibitors, discusses the role of the medically integrated pharmacy team, and suggests strategies that pharmacists can use in patient management and clinical decision-making to optimize the treatment of CP CML.},
	doi = {10.1177/1078155219864640},
	pmid = {31354102 [Indexed for MEDLINE]}
}

@ARTICLE{10.1007/s13187-019-01574-7,
	author = {Berg CJ and Vanderpool RC and Getachew B and Payne JB and Johnson MF and Sandridge Y and Bierhoff J and Le L and Johnson R and Weber A and Patterson A and Dorvil S and Mertens A},
	title = {A Hope-Based Intervention to Address Disrupted Goal Pursuits and Quality of Life Among Young Adult Cancer Survivors.},
	journal = {J Cancer Educ},
	year = {2020},
	abstract = {Over 70,000 US young adults are diagnosed with cancer annually, disrupting important life transitions and goal pursuits. Hope is a positive psychology construct associated with better quality of life (QOL) that focuses on goal-oriented thinking. We developed and tested Achieving Wellness After Kancer in Early life (AWAKE), a scalable 8-week app-based program consisting of educational videos, mood/activity tracking, and telephone-based coaching to promote hope and QOL in young adult cancer survivors (YACS, 18-40 years old). A two-arm RCT was used to examine the feasibility, acceptability, and potential efficacy of AWAKE (n = 38) versus attention control (AC; n = 18) among YACS within 2 years of completing treatment and recruited from two NCI-designated cancer centers. Outcomes including hope (Trait Hope Scale), QOL (36-Item Short Form Health Survey; Functional Assessment of Cancer Therapy-General), depressive symptoms (Patient Health Questionnaire-9), and substance use were assessed at baseline, 8 weeks, and 6 months. Participants were an average of 32.55 (SD = 5.45) years old; 75.0% were female, and 80.4% White. The most common cancers were breast cancer (28.6%), melanoma (16.1%), and leukemia/lymphoma (12.5%). High retention, engagement, and satisfaction rates were documented in both conditions; AWAKE versus AC participants rated video content as more relevant (p = 0.007) and reported greater likelihood of talking positively about the program (p = 0.005). Many efficacy change scores showed positive trends in AWAKE versus AC. Reorienting to one's goal pursuits after cancer diagnosis and treatment is critical and may be supported through hope-based interventions. Findings suggest that the AWAKE warrants subsequent research testing its efficacy, effectiveness, and scalability.},
	doi = {10.1007/s13187-019-01574-7},
	pmid = {31297743 [Indexed for MEDLINE]},
	note = {PMC6954353}
}

@ARTICLE{10.1016/j.critrevonc.2019.05.013,
	author = {Santini V and Ossenkoppele GJ},
	title = {Hypomethylating agents in the treatment of acute myeloid leukemia: A guide to optimal use.},
	journal = {Crit Rev Oncol Hematol},
	year = {2019},
	abstract = {The hypomethylating agents (HMAs), decitabine and azacitidine, are valuable treatment options in acute myeloid leukemia patients who are not eligible for intensive chemotherapy. Both agents are generally well tolerated, and complications most commonly relate to myelosuppression. Antibiotic / antifungal use, regular monitoring, and proactive patient education are important to minimize these events, and reduce the need for dose delay. Responses to HMAs are often not evident for up to 6 cycles, and there is currently no validated clinical marker for predicting response. Hence, treatment should be continued for at least 4-6 cycles to ensure that patients have sufficient opportunity to respond. Delivery of insufficient numbers of cycles is a key reason for HMA failure, and premature discontinuation must be avoided. Genetic factors offer potential for better predicting responders to HMAs in future, but require further study.},
	doi = {10.1016/j.critrevonc.2019.05.013},
	pmid = {31153036 [Indexed for MEDLINE]}
}

