@ARTICLE{10.22034/apjcp.2017.18.7.1925,
	author = {Lim YM and Eng WL and Chan HK},
	title = {Understanding and Challenges in Taking Tyrosine Kinase Inhibitors among Malaysian Chronic Myeloid Leukemia Patients: A Qualitative Study.},
	journal = {Asian Pac J Cancer Prev},
	year = {2017},
	abstract = {Background: In Malaysia, the treatment for chronic myeloid leukemia (CML) has long been delivered under the Malaysian Patient Assistance Program (MYPAP), but research on identifying factors contributing to non-adherence to tyrosine kinase inhibitors (TKIs) is still limited. The current study explored understanding and challenges of Malaysian CML patients in taking imatinib and nilotinib. Methods: Semi-structured, face-to-face interviews were conducted with 13 CML patients receiving treatment at a public tertiary care center, and were analyzed using the content analysis approach. Results: The patients generally demonstrated inadequate knowledge, particularly of the natural history and staging of CML, the function of TKIs, and the methods used for monitoring the effectiveness of treatment. A number of them also had experiences of withholding, skipping or altering the treatment, mainly due to the life-disturbing adverse drug effects (ADRs), forgetfulness, and religious and social issues. Besides, most of them were found having limited skills in managing the ADRs, and not using prompts as reminders to take the medications. Furthermore, even though nilotinib was generally perceived as better tolerated as compared with imatinib, the inconvenience caused by the need to take it twice daily and on an empty stomach was constantly highlighted by the patients. Conclusion: While TKIs are widely used for CML treatment in Malaysia, the findings have revealed a lack of patient education and awareness, which warrants an integrated plan to reinforce medication adherence.},
	doi = {10.22034/apjcp.2017.18.7.1925},
	pmid = {28749622},
	note = {PMC5648400}
}

@ARTICLE{10.1177/1049732316688882,
	author = {Huyard C and Derijks L and Haak H and Lieverse L},
	title = {Intentional Nonadherence as a Means to Exert Control.},
	journal = {Qual Health Res},
	year = {2017},
	abstract = {Medication adherence is a major issue for patients with a chronic illness, who sometimes rationally choose temporary nonadherence. This study aims at better understanding intentional nonadherence and especially why it seems to fluctuate over time. It is based on 48 semi-structured interviews conducted in a hospital in the Netherlands with patients who had been prescribed a medication for a chronic disease for at least 1 year, and who had either type 2 diabetes, hypertension, Parkinson's disease, inflammatory bowel disease, or chronic myeloid leukemia. The analysis uses a simplified version of the failure modes and effects analysis (FMEA) method. Intentional nonadherence appeared to be the result of the respondents' desire (a) to exert control over the treatment and its effects on their body, and (b) to control the hold of the treatment on their daily life. This result provides a rationale for the fluctuation of intentional nonadherence behavior.},
	doi = {10.1177/1049732316688882},
	pmid = {28682739 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/cncr.30862,
	author = {Frick MA and Vachani CC and Bach C and Hampshire MK and Arnold-Korzeniowski K and Metz JM and Hill-Kayser CE},
	title = {Survivorship and the chronic cancer patient: Patterns in treatment-related effects, follow-up care, and use of survivorship care plans.},
	journal = {Cancer},
	year = {2017},
	abstract = {BACKGROUND: The survivorship needs of patients living with chronic cancer (CC) and their use of survivorship care plans (SCPs) have been overlooked and underappreciated. METHODS: A convenience sample of 39,088 SCPs completed for cancer survivors with an Internet-based SCP tool was examined; it included 5847 CC survivors (15%; CC was defined as chronic leukemia and/or recurrent/metastatic cancer of another nature). Patient-reported treatment effects and follow-up care patterns were compared between CC survivors and survivors treated with curative intent (CI). Responses from a follow-up survey regarding SCP satisfaction and use were reviewed. RESULTS: CC survivors had greater odds of experiencing multiple treatment-related effects than survivors treated with CI; these effects included fatigue, cognitive changes, dyspnea, peripheral neuropathy, lymphedema, and erectile dysfunction. Nearly half of CC survivors were managed by an oncologist alone, and they were less likely than CI patients to be comanaged by a primary care provider and an oncologist. Fewer SCPs were generated by health care providers (HCPs) for CC survivors versus CI survivors. A smaller proportion of CC users versus CI users rated their experience and satisfaction with the SCP tool as very good or excellent, and CC users were less likely to share the HCP summary with their health care team. CONCLUSIONS: A substantial number of CC survivors, often considered incurable but treatable, seek survivorship support. Tools to facilitate participation, communication, and coordination of care are valuable for these patients, and future iterations of SCPs should be designed to address the particular circumstances of living with CC. Cancer 2017;123:4268-4276. © 2017 American Cancer Society.},
	doi = {10.1002/cncr.30862},
	pmid = {28654153 [Indexed for MEDLINE]}
}

@ARTICLE{10.12968/bjon.2017.26.10.S20,
	author = {Murthy V and Weaving S and Paneesha S},
	title = {Imbruvica(®)▾(ibrutinib) patient support programme for chronic lymphocytic leukaemia and mantle cell lymphoma.},
	journal = {Br J Nurs},
	year = {2017},
	abstract = {Single-agent ibrutinib is an effective therapy for three types of non-Hodgkin lymphoma: chronic lymphocytic leukaemia (CLL) and small lymphocytic lymphoma, both in relapsed and refractory cases and as a frontline treatment; relapsed and refractory mantle cell lymphoma; and Waldenstrom's macroglobulinaemia in patients who have been treated previously with a different medication. This novel agent has changed the landscape for the aforementioned three subtypes of lymphoma therapies as an oral alternative to traditional chemoimmunotherapy. You&iTM is a no-cost support programme, funded by Janssen, that connects patients taking Imbruvica with a nurse who can answer their questions and help address treatment challenges. This programme offers patients information about their disease, their treatment regimen and side effects management by telephone. The You&i programme was tested at an NHS hospital. Case studies of patients and feedback from health professionals who have used this service show its potential benefits to the patient experience and service delivery.},
	doi = {10.12968/bjon.2017.26.10.S20},
	pmid = {28541116 [Indexed for MEDLINE]}
}

@ARTICLE{10.6004/jadpro.2016.7.2.3,
	author = {Ault PS and Rose PharmD J and Nodzon PhD LA and Kaled ES},
	title = {Bosutinib Therapy in Patients With Chronic Myeloid Leukemia: Practical Considerations for Management of Side Effects.},
	journal = {J Adv Pract Oncol},
	year = {2016},
	abstract = {The past decade has witnessed great advances in the treatment of chronic myeloid leukemia (CML), brought about in large part by the development of BCR-ABL tyrosine kinase inhibitors (TKIs). Bosutinib joins the armamentarium of approved TKIs for the treatment of chronic phase (CP), accelerated phase (AP), and blast phase (BP) Philadelphia chromosome (Ph)-positive CML resistant to or intolerant of prior therapy. Bosutinib has an adverse-event (AE) profile distinct from that of other TKIs. Diarrhea is the predominant toxicity associated with bosutinib treatment; other commonly reported nonhematologic AEs include rash and liver enzyme elevations. Cardiac events, fluid retention, and electrolyte abnormalities are infrequent. Optimal response to bosutinib requires adherence, which depends, in part, upon optimal management of associated toxicities. The oncology clinician can facilitate this process by providing patient education, timely patient follow-up, and close monitoring to promptly identify and manage AEs. Thus, optimal patient management requires a thorough and current understanding of toxicity profiles and AE management paradigms. This review provides an overview of bosutinib safety data derived from ongoing clinical trials and offers practical clinical strategies currently used to manage toxicities associated with bosutinib treatment in patients with Ph-positive CP, AP, and BP CML.},
	doi = {10.6004/jadpro.2016.7.2.3},
	pmid = {28090366},
	note = {PMC5226309}
}

@ARTICLE{10.1016/j.beha.2016.08.008,
	author = {Koffman B and Schorr A},
	title = {The 21st century revolution in CLL: Why this matters to patients.},
	journal = {Best Pract Res Clin Haematol},
	year = {2016},
	abstract = {The 21st century has seen rapid, positive changes in the management of chronic lymphocytic leukaemia from the patient's perspective. New prognostic and predictive markers have ushered in the start of more precise and individualized therapy. For the first time, combined therapy [fludarabine, cyclophosphamide and rituximab] has been shown to prolong life significantly. Clinical trials have become more adaptive, faster and more patient friendly. Perhaps the greatest change of all is the development of novel oral agents (ibrutinib and idelalisib) and powerful monoclonal antibodies that offer robust and durable disease control. Finally, access to and understanding of these changes through an empowered and educated patient population has grown through live education forums and the Internet.},
	doi = {10.1016/j.beha.2016.08.008},
	pmid = {27742066 [Indexed for MEDLINE]}
}

@ARTICLE{10.4137/CMO.S32822,
	author = {Al-Dewik NI and Morsi HM and Samara MM and Ghasoub RS and Gnanam CC and Bhaskaran SK and Nashwan AJ and Al-Jurf RM and Ismail MA and AlSharshani MM and AlSayab AA and Ben-Omran TI and Khatib RB and Yassin MA},
	title = {Is Adherence to Imatinib Mesylate Treatment Among Patients with Chronic Myeloid Leukemia Associated with Better Clinical Outcomes in Qatar?},
	journal = {Clin Med Insights Oncol},
	year = {2016},
	abstract = {BACKGROUND: Despite the revolutionary success of introducing tyrosine kinase inhibitors (TKIs), such as imatinib mesylate (IM), for treating chronic myeloid leukemia (CML), a substantial proportion of patients' treatments fail. AIM: This study investigates the correlation between patient adherence and failure of TKIs' treatment in a follow-up study. METHODS: This is a follow-up study of a new cohort of CML patients. Adherence to IM is assessed using the Medication Event Monitoring System (MEMS 6 TrackCap, AARDEX Ltd). The 9-item Morisky Medication Adherence Scale, medication possession ratio (MPR) calculation, and the electronic medical records are used for identifying potential factors that influence adherence. Clinical outcomes are assessed according to the European Leukemia Net 2013 guidelines via reverse transcriptase quantitative polymerase chain reaction measurement of the level of BCR-ABL1 transcripts in peripheral blood. Response is classified at the hematological, cytogenetic, and molecular levels into optimal, suboptimal, or failure. RESULTS: A total of 36 CML patients (5 citizens and 31 noncitizen residents) consented to participate in the study. The overall mean MEMS score was 89. Of the 36 patients, 22 (61%) were classified as adherent (mean: 95) and 14 (39%) were classified as nonadherent (mean: 80.2). Adherent patients were significantly more likely to obtain optimal response (95%) compared to the nonadherent group (14.3%; P < 0.0001). The rate of poor adherence was as high as 39% using MEMS, which correlates with 37% treatment failure rate. The survey results show that 97% of patients increased the IM dose by themselves when they felt unwell and 31% of them took the missing IM dose when they remembered. Other factors known to influence adherence show that half of patients developed one or more side effects, 65% of patients experienced lack of funds, 13% of patients declared unavailability of the drug in the NCCCR pharmacy, and 72% of patients believed that IM would cure the disease. The MPR results reveal that 16% of patients had poor access to treatment through the hospital pharmacy. DISCUSSION AND CONCLUSION: This is the first prospective study to evaluate CML patients' adherence and response to IM in Qatar. The high rate of treatment failure observed in Qatar is explained by poor adherence. An economic factor (unaffordable drug prices) is one of the main causes of nonadherence and efforts should be made locally to improve access to medication for cancer diseases. Other risk factors associated with poor adherence could be improved by close monitoring and dose adjustment. Monitoring risk factors for poor adherence and patient education that include direct communication between the health-care teams, doctors, nurses, pharmacists, and patients are essential components for maximizing the benefits of TKI therapy and could rectify this problem. The preliminary results show that patients' response to treatment may be directly linked to patients' adherence to treatment. However, further in-depth and specific analysis may be necessary in a larger cohort.},
	doi = {10.4137/CMO.S32822},
	pmid = {27721664},
	note = {PMC5047706}
}

@ARTICLE{10.1371/journal.pone.0155782,
	author = {Pandey D and Kaur S and Kamath A},
	title = {Banking Umbilical Cord Blood (UCB) Stem Cells: Awareness, Attitude and Expectations of Potential Donors from One of the Largest Potential Repository (India).},
	journal = {PLoS One},
	year = {2016},
	abstract = {BACKGROUND: The concept of Umbilical Cord blood (UCB) stem cells is emerging as a non-invasive, efficacious alternative source of hematopoietic stem cells to treat a variety of blood and bone marrow diseases, blood cancers, metabolic disorders and immune deficiencies. Aim of the present study was to determine the level of awareness about banking UCB among pregnant women in India. We also assessed patient perception for banking of UCB and explored the patient expectations of banking UCB in future. This is the first study to assess current attitudes, in a sample population of potential donors from one of the largest potential UCB repository (India). Obtaining this information may help optimize recruitment efforts and improve patient education. MATERIAL AND METHOD: Present explorative questionnaire based survey included 254 pregnant women in the final analysis. RESULTS: We established only 26.5% pregnant women in our study population knew what exactly is meant by UCB. A large proportion (55.1%) was undecided on whether they want to bank UCB or not. Women were more aware of the more advertised private cord blood banking compared to public banking. More than half of the pregnant women expected their obstetrician to inform them regarding UCB. One-third of the women in our population had undue expectations from banking of the UCB. CONCLUSION: Obstetricians should play a more active role in explaining the patients regarding pros and cons of UCB banking.},
	doi = {10.1371/journal.pone.0155782},
	pmid = {27228155 [Indexed for MEDLINE]},
	note = {PMC4881935}
}

@ARTICLE{10.2146/ajhp150749,
	author = {Fajardo S and Zook F and Dotson E},
	title = {Specialty pharmacy for hematologic malignancies.},
	journal = {Am J Health Syst Pharm},
	year = {2016},
	abstract = {PURPOSE: The oral oncology medications used in the treatment of chronic lymphocytic leukemia, chronic myeloid leukemia, multiple myeloma, and non-Hodgkin's lymphoma are reviewed, and the specialty pharmacy services at three large academic medical centers are described. SUMMARY: More than one dozen oral oncology medications are being used for hematologic malignancies and afford patients increased convenience and the potential to improve their quality of life. These agents include ibrutinib, idelalisib, imatinib, dasatinib, nilotinib, bosutinib, ponatinib, thalidomide, lenalidomide, pomalidomide, panobinostat, ixazomib, and vorinostat. Despite the benefits of an autonomous-driven patient care plan, these high-risk, high-cost treatments are not without their challenges. Oral oncology medications are associated with significant barriers to adherence, including low health literacy, patient forgetfulness, complex administration instructions, troublesome adverse effects, and high copayments. Many outpatient cancer center pharmacies associated with large academic medical centers are now applying for specialty pharmacy designation. This affords the onsite dispensing pharmacy access to once-limited oral oncology medications that can be dispensed to clinic patients. In addition, the specialty pharmacy services offered within these cancer centers bridge an important gap in patient care and improve the care provided to oncology patients. CONCLUSION: As oral oncology agents continue to be approved by FDA, oncology treatment teams must establish a comprehensive plan for their management. Because of their pharmacologic expertise, access to patients' medical records, and unique position within ambulatory care oncology teams, pharmacists can play an important role in patient education, laboratory monitoring, medication adherence, and cost saving.},
	doi = {10.2146/ajhp150749},
	pmid = {27126835 [Indexed for MEDLINE]}
}

@ARTICLE{10.1111/jan.12978,
	author = {Kekäle M, Söderlund T and Koskenvesa P and Talvensaari K and Airaksinen M},
	title = {Impact of tailored patient education on adherence of patients with chronic myeloid leukaemia to tyrosine kinase inhibitors: a randomized multicentre intervention study.},
	journal = {J Adv Nurs},
	year = {2016},
	abstract = {AIMS: The aim of this study was to evaluate the influence of tailored patient education on adherence to tyrosine kinase inhibitor medication among patients with chronic myeloid leukaemia. BACKGROUND: Management of chronic myeloid leukaemia has changed dramatically during the last decade. While medication adherence is crucial to clinical response, little is known about how to improve patients' adherence. DESIGN: Randomized multicentre intervention study. METHODS: The study was conducted between June 2012-August 2014. Eighty-six patients with chronic myeloid leukaemia who had been on tyrosine kinase inhibitor medication for at least six months from eight hospitals were randomized into intervention and control groups. Intervention combined nurse-conducted medication counselling, an information booklet, video and website and text message reminders. Patients were interviewed to assess medication adherence using Morisky's 8-Item Medication Adherence Scale at baseline and nine months. RESULTS: Medication adherence improved with the adherence aids used. At nine months, 51% of patients were highly adherent in the intervention group, compared with 21% in the control group. Adherence improved for a higher proportion of patients in the intervention group than the control group (49% vs. 18%). Morisky's score decreased in almost half of control group cases. Patients were most satisfied with face-to-face counselling (86%) and the information booklet (83%) and least satisfied with text messages (9%). CONCLUSION: Tailored patient education improved the medication adherence of patients with chronic myeloid leukaemia. Without this, adherence behaviour tended to decline. Personal communication with a nurse proved to be an essential part of adherence support and should not be ignored.},
	doi = {10.1111/jan.12978},
	pmid = {27113362 [Indexed for MEDLINE]}
}

@ARTICLE{10.6004/jnccn.2016.0035,
	author = {Salsman JM and Yanez B and Smith KN and Beaumont JL and Snyder MA and Barnes K and Clayman ML},
	title = {Documentation of Fertility Preservation Discussions for Young Adults With Cancer: Examining Compliance With Treatment Guidelines.},
	journal = {J Natl Compr Canc Netw},
	year = {2016},
	abstract = {BACKGROUND: Professional guidelines have been developed to promote discussion between providers and newly diagnosed young adults with cancer about the possibility of cancer treatment-related infertility, but previous research suggests many young adults fail to receive this information. The aim of this study was to examine rates of and factors predictive of oncologists' compliance with national guidelines for discussing potential treatment-related infertility with newly diagnosed young adults with cancer seen at an NCI-designated comprehensive cancer center. METHODS: We reviewed data from the electronic medical record for new clinic encounters between medical oncologists and young adults with cancer (ages 18-39 years) from 2010 to 2012. Data from oncologist discussions of fertility preservation were abstracted, as were patient (age, sex, race, ethnicity, cancer type) and oncologist (gender, graduation year from fellowship) characteristics. RESULTS: A total of 1,018 cases were reviewed, with 454 patients (mean, 31.5 years; 67.8% women) meeting inclusion criteria. Overall, 83% of patients were informed about potential treatment-related infertility, with patients with breast cancer (85% informed), Hodgkin lymphoma (95% informed), non-Hodgkin's lymphoma (94% informed), leukemia (88% informed), or testicular cancer (100% informed) more likely to be informed than those with other cancer types (60%-74% informed). There was a significant effect for patient sex (odds ratio, 3.57; CI, 1.33, 9.60; P=.012), with women being more likely to be informed than men. CONCLUSIONS: Reported compliance with fertility preservation guidelines was greater than published rates. Higher compliance rates in female patients and in patients with cancers more common among young adults may reflect greater awareness of fertility-related concerns among these patients and their providers.},
	doi = {10.6004/jnccn.2016.0035},
	pmid = {26957616 [Indexed for MEDLINE]},
	note = {PMC5537734}
}

@ARTICLE{10.1111/jan.12883,
	author = {Bagnasco A and Calza S and Petralia P and Aleo G and Fornoni L and Sasso L},
	title = {Investigating the use of Barrows Cards to improve self-management and reduce healthcare costs in adolescents with blood cancer: a pilot study.},
	journal = {J Adv Nurs},
	year = {2016},
	abstract = {AIM: To test if the Barrows Cards method improves adherence to immunosuppressive therapy self-management following hematopoietic stem-cell transplantation in adolescents affected by blood cancer and reduce costs. BACKGROUND: Chronically ill adolescents need to be helped to improve self-management, make sure they can confidently and safely manage therapy at home and reduce readmissions and costs. We identified the Barrows Cards method, originally used to test decision-making skills and critical thinking in medical students. In this pilot study, we tested the efficacy of the Barrows Cards Method in improving adhesion to immunosuppressive therapy in a group of adolescents following hematopoietic stem-cell transplantation and analysed its cost-effectiveness. DESIGN: A mixed-method study. METHODS: The Barrows Cards method is an educational intervention based on the theory of problem-based learning that uses at least 15 cards specially designed to teach participants how to manage a specific problem. We piloted the Barrows cards method in terms of adherence to immunosuppressive therapy and self-management in a group of 17 adolescents affected by blood cancer before being discharged. Participants were enrolled between 2013-2015. Activity Based Costing was used to analyse the cost-effectiveness. RESULTS: The Barrows Cards method significantly improved adherence to immunosuppressive therapy in blood cancer adolescents and reduced readmissions. We also showed how this method could significantly reduce healthcare costs. CONCLUSIONS: Further research is required, but the Barrows Cards method could be effectively used by nurses to improve self-management in chronic patients and reduce health costs.},
	doi = {10.1111/jan.12883},
	pmid = {26749272 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/ajh.24262,
	author = {Møller T and Moser C and Adamsen L and Rugaard G and Jarden M, Bøtcher TS and Wiedenbein L and Kjeldsen L},
	title = {Early warning and prevention of pneumonia in acute leukemia by patient education, spirometry, and positive expiratory pressure: A randomized controlled trial.},
	journal = {Am J Hematol},
	year = {2016},
	abstract = {Long-lasting neutropenia associated with acute myeloid leukemia (AML) and its treatment gives rise to a high risk of pneumonia. The use of broad-spectrum antibiotic prophylaxis during outpatient management has not completely protected patients against admission due to infections and neutropenic fever, emphasizing the need to approach infection protection with complementary efforts. In a randomized controlled design, we examined the applicability of patient-performed daily spirometry [forced expiratory volume in one second (FEV1)] as an early warning tool and explored the effectiveness of positive expiratory pressure (PEP) in preventing pneumonia among 80 AML patients. Twenty-five incidences of pneumonia were detected among 23 patients (6 interventions, 17 controls), giving a prevalence of 28.75% during 5420 days of observation. We found a significant difference in incidence between intervention versus control group (2.17 per 1000 days vs. 6.52 per 1000 days, P = 0.021, respectively). A cross point at 80-76% of the personal FEV1 reference value showed high sensitivity and specificity on pneumonia development. Our data demonstrate the feasibility of educating AML patients in their continuous daily measurement of FEV1 and use of PEP. Daily measures of FEV1 may be an important early warning tool for assessment of pulmonary deterioration during critical phases of neutropenia. We suggest that strategic patient education in the use of spirometry and PEP should be part of standard of care for AML patients undergoing induction chemotherapy.},
	doi = {10.1002/ajh.24262},
	pmid = {26661344 [Indexed for MEDLINE]},
	note = {PMC5067626}
}

@ARTICLE{10.1007/s00520-015-2843-1,
	author = {Leppla L and De Geest S and Fierz K and Deschler-Baier B and Koller A},
	title = {An oral care self-management support protocol (OrCaSS) to reduce oral mucositis in hospitalized patients with acute myeloid leukemia and allogeneic hematopoietic stem cell transplantation: a randomized controlled pilot study.},
	journal = {Support Care Cancer},
	year = {2016},
	abstract = {INTRODUCTION: Oral mucositis (OM) is a common and debilitating side effect of chemoradiotherapy in patients awaiting allogeneic hematopoietic stem cell transplantation (aHSCT). PURPOSE: The aim of this pilot RCT was to compare an oral care self-management support protocol (OrCaSS) to usual pre-aHSCT care. Feasibility was tested, effect sizes calculated for OM (primary outcome), and patient adherence was measured (secondary outcome). METHODS: Eighteen AML patients awaiting aHSCT and hospitalized between August 2012 and April 2013 were randomized 1:1 to usual care (UCG) and intervention (IG) groups. The OrCaSS protocol consisted of two sessions of educational and behavioral interventions, the first delivered 1 week pre-admission (T1), the second on admission day (T2). Via field notes, practicability and acceptability were evaluated to explore the feasibility of intervention and study procedures. OM data were collected at T1, T2, and daily for 28 days using the WHO scale. The effect size r was calculated (r less than -0.1 ≙ small and greater than or equal to -0.3 ≙ medium). Patients' adherence to the protocol was assessed at T1, T2, and 8-10 days post-HSCT (T3). RESULTS: Research and intervention procedures were feasible. OM incidence was 100 %. The IG's median highest OM grade was 2.0 (IQR = 2); the UCGs was 3.0 (IQR = 2; r = -0.1). Median OM durations were 12 days in the IG and 14 days in the UCG (r = -0.1). OM onset was 2 days later in the IG than in the UCG (r = -0.1). Over the course of the study, patient adherence decreased in both groups. CONCLUSIONS: OrCaSS is a promising intervention to delay and reduce OM. These results can serve to plan a larger RCT.},
	doi = {10.1007/s00520-015-2843-1},
	pmid = {26190359 [Indexed for MEDLINE]}
}
